const o=[{id:"arrays-basics",title:"Arrays — Foundations",topic:"arrays",difficulty:"Beginner",summary:"Indexing, memory layout, and the moves you reach for first.",questions:[{id:"q1",prompt:"Time complexity of reading the element at index i in a Python list?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Lists are array-backed; index access is constant-time pointer arithmetic over a contiguous block."},{id:"q2",prompt:"Worst-case cost of inserting a value at the front of a dynamic array?",options:["O(1)","O(log n)","O(n)","Amortized O(1)"],correct:2,explanation:"Every element behind the insertion point shifts right by one, costing O(n)."},{id:"q3",prompt:"Amortized cost of append on a dynamic array (Python list, Java ArrayList)?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Capacity doubles on overflow, so the cost of occasional resizes spreads across many cheap appends."},{id:"q4",prompt:"You need to reverse an array in place. Lowest extra space possible?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Swap from both ends inward with two pointers — no extra buffer needed."},{id:"q5",prompt:"Finding the maximum element in an unsorted array of n items requires at least how many comparisons?",options:["log n","n / 2","n - 1","n"],correct:2,explanation:"You must rule out every other element exactly once; n - 1 is tight."},{id:"q6",prompt:"Best technique for finding a pair that sums to k in a sorted array?",options:["Two pointers from both ends","Hash map lookup","Binary search per element","Sort then scan"],correct:0,explanation:"Sorted input lets two pointers move inward in O(n) with O(1) extra space."},{id:"q7",prompt:"Which operation is NOT O(1) on a typical dynamic array?",options:["Read by index","Write by index","Append (amortized)","Insert at index 0"],correct:3,explanation:"Inserting at the front shifts every existing element, costing O(n)."},{id:"q8",prompt:"A prefix-sum array of length n + 1 lets you compute any subarray sum in:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"sum(i, j) = prefix[j + 1] - prefix[i] — one subtraction, regardless of length."},{id:"q9",prompt:"Kadane's algorithm solves which problem?",options:["Sorted-array search","Maximum subarray sum","Longest increasing subsequence","Subset sum"],correct:1,explanation:"Kadane sweeps once, keeping a running best-ending-here and a global best — O(n) for max subarray."},{id:"q10",prompt:"Total subarrays of an array of length n?",options:["n","n log n","n(n + 1) / 2","2^n"],correct:2,explanation:"Choose two indices (with order), inclusive: n(n + 1) / 2 contiguous subarrays."},{id:"q11",prompt:"A Python list is internally implemented as a:",options:["Singly linked list","Dynamic array of pointers (over-allocated)","Doubly linked list","Balanced BST"],correct:1,explanation:"CPython stores a contiguous array of PyObject pointers with spare capacity; that is why indexing is O(1) and append is amortized O(1)."},{id:"q12",prompt:"Rotating an array right by k positions in O(n) time and O(1) extra space relies on:",options:["Sort the array","Three reversals (whole, first k, last n - k)","Repeated single-step shifts","A second buffer"],correct:1,explanation:"Reverse everything, then reverse the first k and last n - k. Each element is touched a constant number of times."},{id:"q13",prompt:"Boyer-Moore majority vote finds an element occurring more than n / 2 times in:",options:["O(n) time, O(1) space","O(n log n) time, O(1) space","O(n) time, O(n) space","O(n^2) time, O(1) space"],correct:0,explanation:"A single pass keeps a candidate and a count; pairs of distinct values cancel out, leaving the majority standing."},{id:"q14",prompt:"Why does prefix-sum on an array containing negative numbers still work for subarray-sum queries?",options:["Only positive arrays support prefix sums","Subtraction stays exact regardless of sign — sum(i, j) = prefix[j+1] - prefix[i]","Negatives are wrapped to zero","You need to add a constant offset first"],correct:1,explanation:"Prefix-sum is an algebraic identity; sign of elements doesn't matter. The trap is sliding window, which requires monotonicity."},{id:"q15",prompt:"You write `b = a` for two Python lists. Mutating b also changes a because:",options:["Lists are immutable","Assignment copies the reference, not the contents","Python deep-copies on assignment","List ids are randomized"],correct:1,explanation:"Both names point to the same list object. Use `b = a.copy()`, `b = a[:]`, or `copy.deepcopy(a)` for an independent copy."},{id:"q16",prompt:"A 2-D matrix in row-major order is iterated fastest by:",options:["Column-by-column","Row-by-row (innermost loop walks columns)","Diagonally","Order does not matter"],correct:1,explanation:"Adjacent row elements are contiguous in memory, so row-major iteration maximizes cache-line reuse."},{id:"q17",prompt:"Python's `list.append(x)` is amortized O(1) but a single call can be O(n) because:",options:["Python sorts on append","Capacity overflow triggers a copy into a larger buffer","It checks for duplicates","It locks the GIL"],correct:1,explanation:"When capacity is exhausted, the list grows (typically ~1.125x) and copies all elements — a one-off O(n) pay that amortizes to O(1)."},{id:"q18",prompt:"C++ `std::vector::push_back` and Java `ArrayList.add` both amortize to O(1). The growth factor matters because:",options:["Smaller factors save memory but pay more copies; geometric growth keeps amortized cost constant","Linear growth is faster","Growth factor has no effect","Growth must be a power of two"],correct:0,explanation:"Linear growth gives O(n) amortized append; geometric (doubling, 1.5x) keeps the total copy work O(n) across n appends."},{id:"q19",prompt:"When would you reach for a linked list over a dynamic array?",options:["Heavy random-index access","Frequent insertions/deletions in the middle with an existing pointer to the node","Maximum cache locality","Sorting"],correct:1,explanation:"Splice is O(1) given the node; arrays cost O(n) for mid-insert. Without a pre-existing pointer, traversal already costs O(n)."},{id:"q20",prompt:"Sum of two subarrays of equal length sharing a common element is best computed with:",options:["Brute force in O(n^3)","Prefix sums to make each query O(1) after O(n) preprocessing","A heap","Binary search"],correct:1,explanation:"Once you have prefix[], every contiguous sum costs one subtraction — the standard optimization for repeated range queries."}]},{id:"strings-basics",title:"Strings — Patterns & Pitfalls",topic:"strings",difficulty:"Beginner",summary:"Encoding, immutability, and the algorithms that show up in interviews.",questions:[{id:"q1",prompt:"Two strings are anagrams. The fastest check (assuming small alphabet) runs in:",options:["O(1)","O(n)","O(n log n)","O(n^2)"],correct:1,explanation:"Count character frequencies in a fixed-size array in O(n), then compare counts in O(1)."},{id:"q2",prompt:"Building a string by repeated `+=` inside a Python loop has what worst-case time?",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:2,explanation:"Strings are immutable; each concatenation copies the prefix, so n appends cost O(n^2)."},{id:"q3",prompt:"KMP preprocessing computes which structure?",options:["Suffix array","Failure / longest-proper-prefix-suffix table","Trie of suffixes","Z-array"],correct:1,explanation:"KMP's table records the longest proper prefix that is also a suffix at each position."},{id:"q4",prompt:"Rabin-Karp uses what core idea for substring search?",options:["Hash a sliding window of the text","Binary search the pattern","Build a suffix tree","Greedy character matching"],correct:0,explanation:"A rolling hash lets each window comparison be O(1) amortized; mismatches cost O(1), matches verify in O(m)."},{id:"q5",prompt:"Reversing a string in place in a language with immutable strings requires:",options:["O(1) extra space","O(log n) extra space","O(n) extra space","It is impossible"],correct:2,explanation:"Immutable strings can't be modified, so you allocate a new buffer of size n."},{id:"q6",prompt:"Manacher's algorithm finds the longest palindromic substring in:",options:["O(n)","O(n log n)","O(n^2)","O(n^3)"],correct:0,explanation:"Manacher reuses prior palindrome radii to extend at each center in amortized constant time."},{id:"q7",prompt:"Two-pointer expansion-around-center for longest palindromic substring runs in:",options:["O(n)","O(n log n)","O(n^2)","O(n^3)"],correct:2,explanation:"Each of n centers (or n - 1 even centers) expands up to O(n) characters."},{id:"q8",prompt:"Which data structure is best for prefix lookup over a dictionary of strings?",options:["Hash set","Trie","Balanced BST of strings","Suffix array"],correct:1,explanation:"A trie shares prefixes; lookup costs O(length of query), independent of dictionary size."},{id:"q9",prompt:"Edit distance between two strings of length m and n uses how much memory in the standard DP?",options:["O(1)","O(m + n)","O(m * n)","O(m * n log n)"],correct:2,explanation:"A 2-D table of size m * n holds every subproblem; rolling arrays can reduce to O(min(m, n))."},{id:"q10",prompt:"Why is comparing two strings with `==` in Java sometimes a bug?",options:["It compares lengths only","It compares object references, not character contents","It ignores case","It throws on empty strings"],correct:1,explanation:"`==` checks reference identity; use `.equals()` to compare characters."},{id:"q11",prompt:"A Z-array Z[i] stores:",options:["Length of the longest substring starting at i matching a prefix of the string","Hash of the substring ending at i","Number of distinct characters up to i","Index of the next vowel"],correct:0,explanation:"Z-algorithm computes these values in O(n) and powers pattern matching, period detection, and more."},{id:"q12",prompt:"Why does a polynomial rolling hash use a large prime modulus?",options:["Speed","To spread hash values uniformly and limit collision probability","To preserve order","To enable encryption"],correct:1,explanation:"Modding by a large prime reduces accidental collisions; double hashing with two primes drops them further."},{id:"q13",prompt:'In Java, `"abc" == new String("abc")` evaluates to:',options:["true","false","NullPointerException","Compile error"],correct:1,explanation:"The interned literal and the new instance are different objects; `==` compares references, not contents."},{id:"q14",prompt:"A common trap when checking palindromes is:",options:["Comparing characters with == in Java","Forgetting to normalize case / strip non-alphanumerics when the problem says to","Iterating left to right","Using slicing"],correct:1,explanation:'"A man, a plan, a canal: Panama" is a palindrome only after lowercasing and dropping non-letters. Read the spec carefully.'},{id:"q15",prompt:'Why prefer StringBuilder (Java) or `"".join(parts)` (Python) over `+=` in a loop?',options:["Cleaner syntax","Avoids the O(n^2) cost of repeated allocations on immutable strings","It is required by the language","For thread safety"],correct:1,explanation:"Append-and-join builds the final string once in O(n); `+=` rebuilds the accumulated prefix each iteration."},{id:"q16",prompt:"A trie storing N strings of average length L uses how much memory in the worst case (alphabet size A)?",options:["O(N)","O(N * L)","O(N * L * A)","O(N + L)"],correct:2,explanation:"Each node may carry up to A children. Compressed tries (radix trees) and array-vs-map tradeoffs shrink this constant."},{id:"q17",prompt:"Substring search of pattern p (length m) in text t (length n) using KMP runs in:",options:["O(n * m)","O(n + m)","O(n log m)","O(n)"],correct:1,explanation:"Preprocessing builds the failure table in O(m); matching scans the text once in O(n)."},{id:"q18",prompt:"You need to detect any of K patterns within a single text in one pass. Best fit:",options:["Run KMP K times","Aho-Corasick automaton","Sort the patterns","Binary search the text"],correct:1,explanation:"Aho-Corasick builds a trie + failure links, then sweeps the text in O(n + total pattern length + matches)."},{id:"q19",prompt:'A "string" in JavaScript stores characters as:',options:["UTF-8 bytes","UTF-16 code units (surrogate pairs for chars beyond U+FFFF)","ASCII only","UCS-4 code points"],correct:1,explanation:"JS uses UTF-16; emoji and rare CJK chars span two code units, so `length` may differ from visible character count."},{id:"q20",prompt:"Why is `charAt(i)` in Java O(1) but `str[i]` in Python also O(1)?",options:["Both strings are stored as fixed-width arrays of code units","Both use linked structures","Python uses a trie","Java uses ropes"],correct:0,explanation:"Java's String backs onto a char[] of UTF-16 units; CPython picks 1, 2, or 4 bytes per char (PEP 393) but indexing is still constant."}]},{id:"linked-list-basics",title:"Linked Lists — Pointers In Motion",topic:"linked-list",difficulty:"Beginner",summary:"Singly and doubly linked nodes, classic two-pointer tricks.",questions:[{id:"q1",prompt:"Time to access the kth node of a singly linked list?",options:["O(1)","O(log n)","O(k)","O(n log n)"],correct:2,explanation:"No random access — you walk k pointers from the head."},{id:"q2",prompt:"Insertion at the head of a singly linked list (given a head pointer) costs:",options:["O(1)","O(log n)","O(n)","Amortized O(1)"],correct:0,explanation:"Allocate a node, point its next at head, reseat head. Constant work."},{id:"q3",prompt:"Floyd's cycle detection (tortoise and hare) needs how much extra space?",options:["O(1)","O(log n)","O(n)","O(n^2)"],correct:0,explanation:"Two pointers move at different speeds; no auxiliary set needed."},{id:"q4",prompt:"Reversing a singly linked list in place needs which pointers?",options:["Just current","prev and current","prev, current, next","Stack of all nodes"],correct:2,explanation:"You need next to save the rest of the list before rewriting current.next = prev."},{id:"q5",prompt:"To find the middle of a linked list in one pass:",options:["Use slow and fast pointers","Count length, then walk to length / 2","Reverse and re-walk","Use recursion"],correct:0,explanation:"Fast jumps two; when it hits the end, slow sits on the middle. Single pass."},{id:"q6",prompt:"Merging two sorted linked lists into one sorted list runs in:",options:["O(log n)","O(n + m)","O(n * m)","O((n + m) log (n + m))"],correct:1,explanation:"Walk both heads once, append the smaller — linear in the combined length."},{id:"q7",prompt:"A doubly linked list adds which capability over a singly linked list?",options:["O(1) length","O(1) backward traversal from any node","O(1) random access","Sorted iteration"],correct:1,explanation:"Each node stores prev, so traversal in either direction is constant per step."},{id:"q8",prompt:"Deleting a node when you only have a pointer to it (not the head) requires:",options:["It is impossible without the head","Copy next node's value and skip next","O(n) walk from head first","Reverse the list"],correct:1,explanation:"Overwrite the current node with its successor's value, then bypass the successor."},{id:"q9",prompt:"Reverse a linked list recursively. What is the space complexity?",options:["O(1)","O(log n)","O(n)","O(n^2)"],correct:2,explanation:"Each call frame waits for the recursive return — n frames on the stack."},{id:"q10",prompt:"A sentinel (dummy) head node is most useful because:",options:["It speeds up traversal","It removes special cases for empty list / head deletion","It reduces memory","It enables binary search"],correct:1,explanation:"With a dummy in front, head insertions and deletions look like every other operation — no branching."},{id:"q11",prompt:"After Floyd's detection finds a meeting point, how do you locate the cycle's start?",options:["Walk from the meeting point alone","Reset one pointer to head, advance both one step at a time — they meet at the cycle start","Use a hash set","It cannot be done without extra memory"],correct:1,explanation:"By distance math, the meeting-to-start distance equals the head-to-start distance modulo cycle length."},{id:"q12",prompt:"Detecting a cycle with a hash set vs Floyd's costs:",options:["Both O(1) space","Hash set O(n) space, Floyd's O(1) space — same time","Hash set is faster","Hash set is the only option"],correct:1,explanation:`Both are O(n) time. Floyd's wins on space; hash set wins on simplicity and arbitrary "first repeated node" queries.`},{id:"q13",prompt:"Finding the kth-from-last node in one pass uses:",options:["Two pointers offset by k","Reverse the list","Recursion only","Length then walk to n - k"],correct:0,explanation:"Advance the lead pointer k steps; then move both until the lead hits null. The trailing pointer sits at the answer."},{id:"q14",prompt:"Why does a singly linked list have worse cache performance than a dynamic array?",options:["Linked nodes are scattered across memory; each pointer-chase risks a cache miss","It allocates more bytes","Cache only works on arrays","The compiler refuses to optimize it"],correct:0,explanation:"Arrays sit in contiguous memory and benefit from prefetching; linked lists hop pointers and lose locality."},{id:"q15",prompt:"A common subtle bug when reversing a linked list iteratively is:",options:["Forgetting to save next before overwriting current.next","Allocating a new list","Using too much memory","Recursion depth"],correct:0,explanation:"Once you set current.next = prev, the original successor is lost unless you cached it in next first."},{id:"q16",prompt:"Removing the head with a dummy node is convenient because:",options:["Dummy.next = head.next handles head removal with the same code path as middle removal","Dummy is faster","Dummy uses less memory","It avoids using pointers"],correct:0,explanation:"Without a dummy, head deletion needs special-casing (reseat head). With it, the operation is uniform."},{id:"q17",prompt:"You hold a reference to a non-tail node N in a singly linked list and want O(1) deletion of N. The trick is:",options:["You cannot do it","Copy N.next.val into N, then bypass N.next","Walk back from head","Reverse the list first"],correct:1,explanation:"You can't reach N's predecessor, so you logically delete the next node after copying its data forward. Doesn't work on the tail."},{id:"q18",prompt:"Detecting if two linked lists intersect (shared suffix) without extra memory uses:",options:["Reverse both and compare","Two pointers that switch heads at end — they meet at the intersection or both hit null together","Hash each node","Compare lengths and walk"],correct:1,explanation:"When pointer A finishes list 1, jump to head of list 2 (and vice versa). After equal total travel, they collide at intersection."},{id:"q19",prompt:"Why does C++ `std::list` (doubly linked) provide O(1) `splice` but Python's `collections.deque` does not?",options:["deque is a doubly linked list","deque is a ring of blocks — O(1) at ends only, not arbitrary mid-splice","deque is single-threaded","They are equivalent"],correct:1,explanation:"Python's deque uses a doubly linked list of fixed-size blocks. Mid-list operations cost O(n); ends remain O(1)."},{id:"q20",prompt:"A skip list provides expected O(log n) search by:",options:["Hashing keys","Layered linked lists where higher levels skip over multiple nodes","Storing pointers in a heap","Sorting on every insert"],correct:1,explanation:"Each node is randomly promoted to higher levels; top levels act as express lanes. Used by Redis sorted sets, LevelDB memtables."}]},{id:"stack-basics",title:"Stacks — LIFO Discipline",topic:"stack",difficulty:"Beginner",summary:"Where to reach for a stack and the patterns it unlocks.",questions:[{id:"q1",prompt:"Push and pop on a stack backed by a dynamic array are:",options:["O(1) amortized","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Both operate at the tail; resize costs amortize away."},{id:"q2",prompt:"Which problem maps cleanly to a stack?",options:["Shortest path in a weighted graph","Matching parentheses","Finding the median of a stream","Top-k frequent elements"],correct:1,explanation:"A stack pops the most recent opener to check against each closer — classic application."},{id:"q3",prompt:'The monotonic stack pattern for "next greater element" runs in:',options:["O(n)","O(n log n)","O(n^2)","O(n * sqrt n)"],correct:0,explanation:"Each element is pushed and popped at most once; amortized linear."},{id:"q4",prompt:"Evaluating a postfix (reverse Polish) expression uses a stack of:",options:["Operators","Operands","Parentheses","Tokens"],correct:1,explanation:"Operands stack up until an operator pops two, evaluates, and pushes the result."},{id:"q5",prompt:"A stack implementation guaranteeing O(1) min query alongside push/pop typically uses:",options:["A second stack tracking running minima","A balanced BST","A min-heap","A trie"],correct:0,explanation:"Push current min onto an auxiliary stack; pop in lockstep — both operations stay O(1)."},{id:"q6",prompt:"Largest rectangle in histogram's O(n) solution relies on:",options:["Segment tree","Monotonic stack of indices","Sorting heights","Two pointers"],correct:1,explanation:"A stack of increasing heights resolves each bar's left/right boundaries in amortized O(1)."},{id:"q7",prompt:"A recursive function uses which structure implicitly?",options:["Queue","Heap","Call stack","Hash map"],correct:2,explanation:"Each call pushes a frame; returns pop frames. Tail recursion can sometimes avoid growth."},{id:"q8",prompt:"Iterative DFS traversal of a graph replaces recursion with which structure?",options:["Queue","Stack","Priority queue","Set"],correct:1,explanation:"Explicit stack mirrors the call stack, letting you go deep without overflow risk."},{id:"q9",prompt:"Browser back-button history is naturally modeled by:",options:["Queue","Stack","Hash table","Heap"],correct:1,explanation:"Most recent page returned first — last in, first out."},{id:"q10",prompt:"Converting infix to postfix (Shunting-yard) uses a stack for:",options:["Operands","Operators","Both, in two separate stacks","Neither — it uses queues only"],correct:1,explanation:"Operators wait on a stack until precedence forces them out into the output queue."},{id:"q11",prompt:'The "next smaller element" pattern uses a monotonic stack of which kind?',options:["Strictly increasing","Strictly decreasing","Non-monotonic","Sorted with binary search"],correct:0,explanation:'Keep an increasing stack; when a smaller value arrives, all larger entries above it pop and learn their "next smaller".'},{id:"q12",prompt:"Why does the monotonic-stack approach give amortized O(n) even though the inner loop pops?",options:["Each element is pushed and popped at most once across the entire scan","Pops are O(log n)","The stack is fixed size","Pops are O(1) but rare"],correct:0,explanation:"Total push + pop work is bounded by 2n, regardless of how busy any single iteration looks."},{id:"q13",prompt:"A common bug in balanced-parentheses validation is:",options:["Pushing closers","Forgetting to check the stack is empty at the end","Using a deque","Sorting the input"],correct:1,explanation:'"(((" passes the popping loop without errors but leaves three openers on the stack — must verify empty.'},{id:"q14",prompt:"Implementing a stack with two queues makes which operation expensive?",options:["Push (or pop, depending on variant) becomes O(n)","Both stay O(1)","Peek becomes O(n)","Nothing — same as one queue"],correct:0,explanation:"You shuffle all but one element between queues to expose the most recent. Either push or pop pays the O(n) cost."},{id:"q15",prompt:"Trapping rain water can be solved with a stack by:",options:["Sorting heights","Pushing indices, popping when a taller bar arrives to fill the basin between previous and current","BFS","A heap of heights"],correct:1,explanation:"Each popped index contributes water bounded by min(prev tall, current) - its own height, times the horizontal gap."},{id:"q16",prompt:"Daily-temperatures (days until a warmer day) is O(n) using:",options:["Two nested loops","Monotonic decreasing stack of unresolved indices","Hash map of temperatures","Sort + scan"],correct:1,explanation:"Push indices; when today is warmer than the top, pop and record the gap. Each index pushed and popped once."},{id:"q17",prompt:"Why might explicit-stack iterative DFS be preferred over recursive DFS on a huge graph?",options:["It is faster","Avoids stack-overflow from deep recursion (e.g., chain of 100k nodes)","It uses less memory","It guarantees shortest path"],correct:1,explanation:"Languages cap recursion depth (Python ~1000); an explicit heap-allocated stack scales to the memory limit."},{id:"q18",prompt:"Stack peek (look at top without popping) on a list-backed stack in Python is:",options:["stack[-1]","stack[0]","stack.pop() then push back","Not supported"],correct:0,explanation:"Negative indexing returns the last element in O(1). pop+push works but mutates and risks errors on empty."},{id:"q19",prompt:"A function-call trace (stack frames) gives which property?",options:["Frames return in FIFO order","Frames return in LIFO order — newest call returns first","Frames return in priority order","Frames are random"],correct:1,explanation:"The most recently pushed frame is the next to pop on return — LIFO is the defining behavior of a stack."},{id:"q20",prompt:'When solving "valid parentheses" with three bracket types, the right structure is:',options:["Stack of openers; on each closer, verify it matches the top opener","Counter per type","Sort then match","Two queues"],correct:0,explanation:'Counters alone miss interleaving like "([)]". The stack preserves nesting structure.'}]},{id:"queue-basics",title:"Queues — FIFO & Variants",topic:"queue",difficulty:"Beginner",summary:"Plain queues, deques, and where each one earns its keep.",questions:[{id:"q1",prompt:"Enqueue and dequeue on a well-implemented queue run in:",options:["O(1)","O(log n)","O(n)","Amortized O(log n)"],correct:0,explanation:"A linked-list or ring-buffer queue performs both in constant time."},{id:"q2",prompt:"BFS uses which data structure to manage the frontier?",options:["Stack","Queue","Heap","Set"],correct:1,explanation:"FIFO ordering guarantees we expand nodes in non-decreasing distance from the source."},{id:"q3",prompt:"A deque supports O(1) operations at:",options:["Only the front","Only the back","Both ends","Any index"],correct:2,explanation:"Double-ended queues add at front or back in constant time; mid-array access remains O(n)."},{id:"q4",prompt:"Sliding-window maximum in O(n) uses which structure?",options:["Heap","Monotonic deque","Sorted set","Two stacks"],correct:1,explanation:"A deque of decreasing indices lets the front hold the current window's max — amortized linear."},{id:"q5",prompt:"Using a plain Python list as a queue with `pop(0)` is bad because:",options:["It throws errors","pop(0) is O(n)","It cannot store mixed types","It is not thread-safe"],correct:1,explanation:"pop(0) shifts every remaining element. Use collections.deque for O(1) popleft."},{id:"q6",prompt:"A circular (ring) buffer fixes which downside of a naive array-backed queue?",options:["It allows random access","It avoids shifting elements after dequeue","It sorts entries","It supports priority"],correct:1,explanation:"Front and rear indices wrap modulo capacity, so no element shifting is needed."},{id:"q7",prompt:"A priority queue's typical backing structure is:",options:["Linked list","Hash map","Binary heap","Trie"],correct:2,explanation:"Binary heaps give O(log n) push/pop and O(1) peek of the extremum."},{id:"q8",prompt:"BFS finds shortest paths in:",options:["Weighted DAGs","Unweighted graphs","Graphs with negative edges","Any weighted graph"],correct:1,explanation:"Each edge counts as one hop; FIFO order matches BFS's layer-by-layer expansion."},{id:"q9",prompt:"Implementing a queue with two stacks gives what amortized cost per operation?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Each element moves between the stacks at most once across its lifetime."},{id:"q10",prompt:"A task scheduler that always serves the oldest pending task uses:",options:["Stack","Queue","Heap by priority","Hash set"],correct:1,explanation:"First in, first out — exactly what a FIFO queue provides."},{id:"q11",prompt:"Why is `collections.deque` preferred over `queue.Queue` for single-threaded BFS in Python?",options:["queue.Queue is slower because it acquires locks for thread safety","deque cannot hold large data","queue.Queue lacks popleft","They are identical"],correct:0,explanation:"queue.Queue is synchronized for multi-producer/consumer use; that overhead is wasted in single-threaded BFS."},{id:"q12",prompt:"A monotonic deque differs from a plain deque because it:",options:["Only allows pushes","Maintains an ordered invariant by evicting elements that violate it","Is sorted","Uses two pointers"],correct:1,explanation:"For sliding-window max, pushes pop smaller back elements so the deque stays decreasing — front is always the max."},{id:"q13",prompt:"In multi-source BFS, why seed all sources at distance 0 instead of running BFS per source?",options:["Saves a factor of k where k is the number of sources, while computing the minimum distance to ANY source","It is simpler to write","Avoids cycles","Required by the queue ADT"],correct:0,explanation:"One sweep replaces k separate sweeps. Each cell's first dequeue is its nearest-source distance."},{id:"q14",prompt:"A ring buffer's full vs empty state is often distinguished by:",options:["Reserving one empty slot, or by tracking a count separately","Magic numbers in the data","Sorting periodically","Hashing pointers"],correct:0,explanation:"With front == rear, you can't tell full from empty without an extra bit. Reserving a slot or storing length resolves it."},{id:"q15",prompt:"Python's `queue.PriorityQueue` puts which item out first?",options:["Largest","Smallest (min-heap semantics)","Most recently added","Random"],correct:1,explanation:"It is a min-heap. For max behavior, negate priorities or push (-priority, item) tuples."},{id:"q16",prompt:"A common pitfall when using a heap with tuples for a tie-breaker is:",options:["Tuples are unhashable","If priorities tie, Python compares the next field — non-comparable objects raise TypeError","Heaps reject tuples","Tuples cost O(n) to compare"],correct:1,explanation:"Use (priority, counter, item) — a monotonically increasing counter avoids comparing the items themselves on ties."},{id:"q17",prompt:"When BFS is preferred over DFS:",options:["You need shortest unweighted paths or level-order results","You want minimum memory","You need stable traversal","You want recursion"],correct:0,explanation:"BFS explores layer by layer; DFS may dive far past the goal. For shortest-hop questions, BFS is the canonical choice."},{id:"q18",prompt:"Memory of BFS on a complete binary tree with n nodes can grow to:",options:["O(1)","O(log n)","O(n) — the bottom level alone holds ~n/2 nodes","O(n^2)"],correct:2,explanation:"The frontier balloons to roughly half the tree at the deepest level — a trap when memory is tight; DFS uses O(height) space."},{id:"q19",prompt:"A Round-Robin scheduler maps cleanly to:",options:["Stack","Queue (or circular queue)","Heap","Hash table"],correct:1,explanation:"Each task gets a fixed time slice; finished-but-not-done tasks go back to the tail. FIFO ordering with optional re-enqueue."},{id:"q20",prompt:"Implementing a queue from two stacks: the amortized cost holds because:",options:["Each element moves between stacks at most once over its lifetime","Pop is always O(1)","Stacks are sorted","The number of stacks is two"],correct:0,explanation:"A given element pays its O(n) move only once when the output stack drains; amortizing across all ops yields O(1) per op."}]},{id:"hashmap-basics",title:"Hash Maps — Lookups Without Sorting",topic:"hashmap",difficulty:"Beginner",summary:"Average-case wins, worst-case traps, and the patterns that lean on them.",questions:[{id:"q1",prompt:"Average-case lookup in a hash map is:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"With a good hash and bounded load factor, expected probe length is constant."},{id:"q2",prompt:"Worst-case lookup with adversarial hash collisions is:",options:["O(1)","O(log n)","O(n)","O(n^2)"],correct:2,explanation:"All keys collide into one bucket, degenerating into a linear scan."},{id:"q3",prompt:"Two Sum on an unsorted array using a hash map runs in:",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:0,explanation:"One pass: for each x, check if target - x is in the map; otherwise insert x."},{id:"q4",prompt:"Open addressing handles collisions by:",options:["Chaining a linked list per bucket","Probing for the next empty slot","Rehashing the entire table","Switching to a tree"],correct:1,explanation:"Linear, quadratic, or double-hashing probes find another slot inside the same array."},{id:"q5",prompt:"A hash set differs from a hash map in that it:",options:["Stores only keys, no associated values","Allows duplicates","Sorts entries","Is slower"],correct:0,explanation:"Sets care about membership only — same lookup mechanics, no value field."},{id:"q6",prompt:"Why does Python's dict resize when load factor exceeds a threshold?",options:["To save memory","To keep collision rates low","To sort entries","To enable iteration"],correct:1,explanation:"More buckets means fewer expected collisions per insert; amortized O(1) ops require it."},{id:"q7",prompt:"Grouping anagrams together using a hash map keys on:",options:["Original word","Sorted character string","Word length","Hash of the word"],correct:1,explanation:"Two words are anagrams iff their sorted forms match — perfect canonical key."},{id:"q8",prompt:"A hash map's keys must be:",options:["Comparable","Hashable (and equality-defined)","Immutable strings only","Integers"],correct:1,explanation:"Hash and equality let the table find a key reliably; mutable keys would invalidate buckets."},{id:"q9",prompt:"Counting word frequencies in a text in expected linear time uses:",options:["Sort then scan","Hash map","Trie","Heap"],correct:1,explanation:"For each word, increment its hash-map counter — O(1) expected per token."},{id:"q10",prompt:"Java 8's HashMap converts long collision chains into a balanced tree to ensure:",options:["O(1) worst case","O(log n) worst case","O(n) worst case","Constant memory"],correct:1,explanation:"Above a bucket-size threshold, chains become red-black trees so worst-case lookup is O(log n)."},{id:"q11",prompt:'A "load factor" of 0.75 in a hash table means:',options:["75% of slots are filled before resize triggers","There are 0.75 entries per bucket on average","Memory usage is 75% of array","Probability of collision is 75%"],correct:0,explanation:"Once entries / buckets exceeds the threshold, the table doubles to keep expected probe length bounded."},{id:"q12",prompt:"Why does mutating a key already inside a hash map break lookups?",options:["It does not — keys can mutate freely","Mutation changes hash; the key is now in the wrong bucket and unfindable","It throws immediately","It corrupts the table"],correct:1,explanation:"The table indexed by the old hash; the new hash points elsewhere. Always use immutable / frozen keys."},{id:"q13",prompt:"Longest consecutive sequence in O(n) uses a hash set because:",options:["It allows starting expansion only from elements that have no smaller neighbor","Sets are sorted","Sets support range queries","Sets store duplicates"],correct:0,explanation:"For each x, only walk if x - 1 isn't present — that pins exactly one start per run, giving amortized O(n)."},{id:"q14",prompt:"A subtle Two-Sum bug is:",options:["Using a list","Returning indices of the same element twice when target = 2 * x","Hashing the wrong key","Forgetting to sort"],correct:1,explanation:"Check the complement BEFORE inserting x, so the map can't match x against itself."},{id:"q15",prompt:"Chaining vs open addressing — which is more memory-efficient under high load factor?",options:["Open addressing — no per-entry pointer overhead","Chaining — fewer collisions","Both equal","Neither works at high load"],correct:0,explanation:"Chaining stores list/tree nodes per bucket; open addressing keeps entries inline. Open addressing also has better cache locality."},{id:"q16",prompt:"Why is comparing two hash maps for equality O(n)?",options:["You must verify each key/value pair matches","Hash comparison is O(n)","Maps are sorted internally","They iterate in insertion order"],correct:0,explanation:"Even if sizes match, you must look up every key in the other map. No shortcut without a digest."},{id:"q17",prompt:"A LRU cache supports O(1) get/put using:",options:["Hash map alone","Hash map + doubly linked list (map node -> list node, list maintains recency)","Heap","BST"],correct:1,explanation:"Map locates the node in O(1); doubly linked list lets you splice it to the front in O(1). Both required."},{id:"q18",prompt:"Python's dict preserves insertion order since:",options:["Python 3.7 (guaranteed by language spec; 3.6 by implementation detail)","Python 2.7","Python 3.10","Never"],correct:0,explanation:"Use `collections.OrderedDict` only if you need its extra methods like move_to_end; for ordering alone, plain dict suffices."},{id:"q19",prompt:"A perfect hash function is one that:",options:["Always uses minimal memory","Has no collisions for the given key set","Is cryptographic","Is order-preserving"],correct:1,explanation:"Perfect hashing is achievable for a known static key set — e.g., GCC switch-on-string optimization uses gperf."},{id:"q20",prompt:"When would a sorted structure (BST, sorted list) beat a hash map?",options:["Range queries (find all keys in [a, b]), or repeated min/max queries","Single-key lookup","Insertion speed","Memory efficiency"],correct:0,explanation:"Hash maps lose ordering; range and successor queries cost O(n). BSTs and skip lists handle them in O(log n + k)."}]},{id:"tree-basics",title:"Trees — Recursion in Structure",topic:"tree",difficulty:"Beginner",summary:"Binary trees, traversals, height, and the recursive habit they teach.",questions:[{id:"q1",prompt:"In-order traversal of a binary tree visits nodes in what order?",options:["Root, left, right","Left, root, right","Left, right, root","Root, right, left"],correct:1,explanation:"Left subtree, then current node, then right subtree — yields sorted order for a BST."},{id:"q2",prompt:"Height of a balanced binary tree with n nodes is:",options:["O(1)","O(log n)","O(sqrt n)","O(n)"],correct:1,explanation:"Balance keeps each level roughly twice the previous, so depth grows logarithmically."},{id:"q3",prompt:"Worst-case height of an unbalanced binary tree?",options:["O(1)","O(log n)","O(sqrt n)","O(n)"],correct:3,explanation:"A degenerate chain (every node has one child) makes height equal to n."},{id:"q4",prompt:"Level-order (BFS) traversal of a binary tree uses a:",options:["Stack","Queue","Heap","Recursion only"],correct:1,explanation:"A FIFO queue holds each level's nodes; popping yields children in level order."},{id:"q5",prompt:"Counting all nodes in a binary tree recursively runs in:",options:["O(log n)","O(n)","O(n log n)","O(n^2)"],correct:1,explanation:"Each node is visited exactly once."},{id:"q6",prompt:"A full binary tree of height h has at most how many nodes?",options:["h","2h","2^h - 1","h^2"],correct:2,explanation:"Levels 0..h-1 each double; total = 1 + 2 + 4 + ... + 2^(h-1) = 2^h - 1."},{id:"q7",prompt:"Lowest Common Ancestor in a generic binary tree (no parent pointers) typically runs in:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:2,explanation:'A single recursive post-order pass propagates "found p or q" upward in O(n).'},{id:"q8",prompt:"Diameter of a binary tree is:",options:["Number of nodes","Number of leaves","Longest path between any two nodes","Maximum depth"],correct:2,explanation:"Longest path (edges) between any two nodes — often computed as max(left height + right height) per node."},{id:"q9",prompt:'A serialized "preorder + inorder" pair uniquely reconstructs a binary tree because:',options:["Preorder gives the root, inorder splits left/right subtrees","Inorder sorts the values","Preorder is unique to balanced trees","It always assumes a BST"],correct:0,explanation:"Preorder's first element is the root; finding it in inorder partitions the remaining nodes into subtrees."},{id:"q10",prompt:"A complete binary tree differs from a full binary tree because:",options:["It has no leaves","All levels except possibly the last are full, and the last fills left to right","Every node has exactly two children","It is always balanced"],correct:1,explanation:"Complete = filled top-down, left-to-right. Full = every internal node has two children. They overlap but differ."},{id:"q11",prompt:"Morris in-order traversal achieves O(1) extra space by:",options:["Recursion","Threading the rightmost node of each left subtree back to its in-order successor","A heap","Hash map"],correct:1,explanation:"Temporarily rewire null right pointers to point to successors; restore them as traversal returns."},{id:"q12",prompt:"Maximum number of nodes at depth d in a binary tree?",options:["d","2d","2^d","d^2"],correct:2,explanation:"Each level doubles in capacity; root is 2^0 = 1, depth d holds up to 2^d."},{id:"q13",prompt:"Recursive height computation has space complexity:",options:["O(1)","O(log n) for balanced, O(n) worst case","Always O(n)","O(log n) always"],correct:1,explanation:"The call stack mirrors the tree height. Balanced trees give log n; degenerate chains push n frames."},{id:"q14",prompt:"Why does iterative pre-order use a stack but iterative in-order requires extra care?",options:["Pre-order pushes children directly; in-order must dive left first before processing the node","In-order requires recursion","Pre-order needs more memory","In-order is impossible iteratively"],correct:0,explanation:'In-order needs a "go left as far as possible, then visit, then turn right" loop — typically with a stack of pending nodes.'},{id:"q15",prompt:"Lowest Common Ancestor for k nodes in a tree (not BST) is solved by:",options:["Post-order recursion returning the count of target nodes found in each subtree","BFS","Sort nodes","Hash map"],correct:0,explanation:"The first node whose subtrees collectively cover all k targets is the LCA."},{id:"q16",prompt:'Serializing a binary tree with preorder + nulls (e.g., "1 2 # # 3 # #") works because:',options:["Nulls mark subtree boundaries, making the structure unambiguous","Preorder alone suffices","It is alphabetic","It is sorted"],correct:0,explanation:"Without nulls, you need a second traversal (inorder) to reconstruct shape; explicit null markers remove ambiguity."},{id:"q17",prompt:"A binary tree with all leaves at the same depth is called:",options:["Complete","Perfect","Full","Degenerate"],correct:1,explanation:"Perfect: every internal node has two children AND all leaves share depth. Strict superset of complete and full."},{id:"q18",prompt:"Right-side view (one node per level, rightmost visible) is naturally computed by:",options:["BFS recording the last node at each level","In-order","DFS with no level tracking","Hash map of depths"],correct:0,explanation:"Alternatively, DFS visiting right child first and capturing the first node seen per depth works too."},{id:"q19",prompt:"Checking if two trees are identical recursively returns true when:",options:["Both are null, or both non-null with equal values AND identical left and right subtrees","Roots are equal","They have the same node count","They have the same height"],correct:0,explanation:"Structural recursion; node-count or height equality is necessary but far from sufficient."},{id:"q20",prompt:"Why prefer iterative DFS over recursive on a tree of depth ~1e6?",options:["It uses fewer comparisons","Recursion would blow the language's stack limit; explicit stack is heap-allocated","Iterative is always faster","Recursion has worse asymptotic complexity"],correct:1,explanation:"Python's default recursion limit is ~1000; JVM/.NET stacks are MB-scale. Heap-allocated stacks scale far further."}]},{id:"bst-basics",title:"BSTs — Ordered Trees",topic:"bst",difficulty:"Intermediate",summary:"Ordering invariants, search costs, and what balance buys you.",questions:[{id:"q1",prompt:"Average search time in a balanced BST with n nodes is:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:1,explanation:"Each step rules out one subtree; height is O(log n) when balanced."},{id:"q2",prompt:"In-order traversal of a BST produces:",options:["Pre-order","Sorted ascending sequence","Reverse-sorted sequence","Random order"],correct:1,explanation:"For every node, left subtree < node < right subtree, so in-order yields ascending values."},{id:"q3",prompt:"A BST built from already-sorted inserts becomes:",options:["Balanced","A degenerate chain (O(n) height)","A complete tree","Empty"],correct:1,explanation:"Each new key is larger than all current keys, so it always becomes the rightmost child."},{id:"q4",prompt:"Deletion of a node with two children in a BST replaces it with:",options:["Its left child","Its right child","In-order successor (or predecessor)","Its parent"],correct:2,explanation:"The successor preserves the BST order: smallest value greater than the removed key."},{id:"q5",prompt:"Which structure self-balances after every insert/delete to keep height O(log n)?",options:["Plain BST","Red-Black tree","Binary heap","Trie"],correct:1,explanation:"Red-black (and AVL) trees apply rotations + recoloring to maintain logarithmic height."},{id:"q6",prompt:"Validating that an arbitrary binary tree is a BST requires:",options:["Checking each node vs its children only","Tracking (min, max) bounds during recursion","A single in-order pass into an array","Counting nodes"],correct:1,explanation:"Local checks fail in cases like 10 with right child 15 whose left child is 6. Bounds propagate the constraint."},{id:"q7",prompt:"Successor of a BST node WITH a right subtree is:",options:["Its parent","The minimum of its right subtree","The maximum of its left subtree","The root"],correct:1,explanation:"Smallest value greater than the node lives at the leftmost descendant of its right subtree."},{id:"q8",prompt:"Inserting n random keys into a BST yields expected height of:",options:["O(1)","O(log n)","O(sqrt n)","O(n)"],correct:1,explanation:"Random insertion order gives expected O(log n) height; worst-case sorted order is still O(n)."},{id:"q9",prompt:"Range query (count keys in [a, b]) on a balanced BST with augmented size info runs in:",options:["O(1)","O(log n)","O(n)","O(b - a)"],correct:1,explanation:"Two rank queries (rank(b) - rank(a)) give the count; each rank is O(log n)."},{id:"q10",prompt:"A treap combines BST ordering with which secondary property?",options:["Heap order on random priorities","Hash buckets","Color invariants","Level ordering"],correct:0,explanation:"Treaps assign random priorities and maintain heap order on them, giving expected O(log n) operations."},{id:"q11",prompt:"AVL trees differ from red-black trees primarily in:",options:["AVL enforces stricter balance (height differ by ≤ 1), giving faster lookups but more rotations on insert","AVL allows duplicates, RB doesn't","AVL is unbalanced","RB is faster to query"],correct:0,explanation:"AVL favors read-heavy workloads; red-black is favored where insertions/deletions are frequent (e.g., Java TreeMap, C++ std::map)."},{id:"q12",prompt:"kth smallest element in a BST with size-augmented nodes runs in:",options:["O(k)","O(log n) — descend using subtree sizes","O(n)","O(n log n)"],correct:1,explanation:"At each node, compare k to left-subtree size to decide left, current, or right — pure tree-descent in height time."},{id:"q13",prompt:"A common BST-validation bug is:",options:["Comparing each node only to its immediate children","Using recursion","Using in-order traversal","Checking bounds"],correct:0,explanation:"Node 10 with right child 15 whose left child is 6 passes local checks but breaks the global BST property. Use (min, max) bounds."},{id:"q14",prompt:"Converting a sorted array to a height-balanced BST takes:",options:["O(n log n)","O(n) — recursively pick middle as root","O(n^2)","O(log n)"],correct:1,explanation:"Each element becomes a node exactly once; the recursion partitions evenly so each is touched O(1) times."},{id:"q15",prompt:"Predecessor of a BST node with NO left subtree is:",options:["Smallest in right subtree","Nearest ancestor whose right subtree contains the node","Root","Parent always"],correct:1,explanation:"Climb until you come from a right child — that ancestor is the in-order predecessor."},{id:"q16",prompt:"In-order traversal of a BST yields sorted output. The converse (any sorted-output traversal makes it a BST) is:",options:["True for all trees","False — only in-order on a valid BST produces sorted output","True if balanced","True if augmented"],correct:1,explanation:"A non-BST tree could be lucky enough to have one traversal sort by coincidence, but in-order won't produce sorted output in general unless the BST property holds."},{id:"q17",prompt:"Why is a BST insertion not generally O(log n) in the worst case?",options:["It is O(log n) always","Without rebalancing, repeated sorted inserts make height O(n)","It needs hashing","Insertion always rotates"],correct:1,explanation:"Plain BSTs degenerate on adversarial input. Self-balancing variants (AVL, RB, treap) restore the O(log n) guarantee."},{id:"q18",prompt:"Java's TreeMap implements which BST variant?",options:["AVL","Red-black","Splay","B-tree"],correct:1,explanation:"Red-black trees give O(log n) worst-case for get/put/remove and amortize rotations well under bursty workloads."},{id:"q19",prompt:"A splay tree promises which behavior on repeated access to the same key?",options:["O(log n) per access","Amortized O(log n); recently accessed nodes move toward the root for cheap re-access","O(1) per access","O(n) per access"],correct:1,explanation:"Splaying restructures the tree on every access; hot keys cluster near the root, giving good real-world locality."},{id:"q20",prompt:"Finding two values that sum to k in a BST uses:",options:["Two in-order traversals (forward + backward) as two pointers","BFS","Hash all values then check","Sort the BST first"],correct:0,explanation:"In-order from leftmost (ascending) and reverse in-order from rightmost (descending) act like two pointers in O(n) time, O(h) space."}]},{id:"heap-basics",title:"Heaps & Priority Queues",topic:"heap",difficulty:"Intermediate",summary:"Binary-heap invariants and where the priority queue is the right hammer.",questions:[{id:"q1",prompt:"Peek (look at the min of a min-heap) costs:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"The extremum sits at the root — no traversal needed."},{id:"q2",prompt:"Push and pop on a binary heap of n items are:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:1,explanation:"Sift-up or sift-down traverses one root-to-leaf path of height log n."},{id:"q3",prompt:"Building a heap from an unsorted array of n elements runs in:",options:["O(n log n)","O(n)","O(log n)","O(n^2)"],correct:1,explanation:"Bottom-up heapify is amortized linear; the leaves (most of the nodes) sift zero levels."},{id:"q4",prompt:"Heap sort runs in:",options:["O(n)","O(n log n) worst case","O(n^2) worst case","O(n log n) average, O(n^2) worst"],correct:1,explanation:"Build heap in O(n), then n extract-mins at O(log n) each — guaranteed O(n log n)."},{id:"q5",prompt:"Top-k largest from a stream uses which heap?",options:["Max-heap of size n","Min-heap of size k","Max-heap of size k","Two heaps"],correct:1,explanation:"Keep the k largest in a min-heap; if a new item exceeds the root, replace it. O(log k) per element."},{id:"q6",prompt:"Merging k sorted lists optimally uses:",options:["Merge two at a time","Heap of k current heads","Quicksort the concatenation","Hash map"],correct:1,explanation:"A k-sized heap of the smallest unmerged head from each list gives O(N log k) where N is total items."},{id:"q7",prompt:"Find the running median of a stream uses:",options:["One sorted list","A max-heap of the lower half plus a min-heap of the upper half","A balanced BST only","A counting array"],correct:1,explanation:"Two heaps balanced in size — the median is the root of one (or average of both roots when even)."},{id:"q8",prompt:"Dijkstra's algorithm uses a priority queue keyed on:",options:["Edge weight","Tentative distance from source","Vertex degree","Vertex id"],correct:1,explanation:"The smallest tentative distance pops first; that lets us finalize that vertex."},{id:"q9",prompt:"A binary heap is typically stored as:",options:["Linked nodes","An array with parent/child by index arithmetic","A hash map","A balanced BST"],correct:1,explanation:"Children of index i live at 2i + 1 and 2i + 2 — no pointers needed, great cache locality."},{id:"q10",prompt:"A heap is NOT useful for:",options:["Repeatedly extracting the smallest item","Range queries by key","Top-k selection","Scheduling by priority"],correct:1,explanation:"Heaps order only by extremum; arbitrary range queries need a sorted structure (BST or sorted array)."},{id:"q11",prompt:"Why is bottom-up heapify O(n) instead of O(n log n)?",options:["It skips half the elements","Most nodes (leaves) sift zero levels; sum of work over depths is bounded by 2n","Cache effects","It only processes the root"],correct:1,explanation:"Sum_{h=0..log n} (n / 2^(h+1)) * h converges to O(n) by the geometric series bound."},{id:"q12",prompt:"Python's `heapq` provides only a min-heap. For a max-heap, the typical trick is:",options:["Use heapq._heapify_max (private)","Negate priorities on push and pop","Sort the heap after each push","Switch to sortedcontainers"],correct:1,explanation:"Push (-val) and negate on pop; for tuples, negate the priority field. Cleaner than relying on private APIs."},{id:"q13",prompt:"Decrease-key on a binary heap is:",options:["O(1)","O(log n) given the index, but finding the index is O(n) without an external map","O(n) always","Not supported"],correct:1,explanation:"That's why Dijkstra with a binary heap and lazy deletion (push-with-stale-skip) is more common than true decrease-key."},{id:"q14",prompt:"A common bug when storing (priority, item) tuples in a heap is:",options:["Forgetting that ties trigger comparison of `item`, which may be non-comparable","Tuples are not hashable","Tuples cannot be heaped","Comparison is too slow"],correct:0,explanation:"Insert (priority, unique_counter, item) — the counter breaks ties deterministically without touching the payload."},{id:"q15",prompt:"For top-k SMALLEST elements, use:",options:["Min-heap of size k","Max-heap of size k","Min-heap of all n","Sort and take first k"],correct:1,explanation:"Max-heap evicts its (largest) root when a smaller element arrives; the heap holds the k smallest in O(n log k)."},{id:"q16",prompt:"Why is heap-sort O(n log n) worst case while quicksort is O(n^2)?",options:["Heap-sort never depends on pivot choice; sift operations are bounded by tree height log n","Quicksort is recursive","Heap-sort skips comparisons","They are equivalent"],correct:0,explanation:"Heap-sort's guarantee is structural. Quicksort's worst case requires adversarial input or naive pivot choice."},{id:"q17",prompt:"A Fibonacci heap improves which Dijkstra operation asymptotically?",options:["Push from O(log n) to O(1) amortized; decrease-key to O(1) amortized","Pop becomes O(1)","Peek becomes O(log n)","Nothing"],correct:0,explanation:"Decrease-key in O(1) amortized makes Dijkstra O(E + V log V). Constants are large enough that binary heaps usually win in practice."},{id:"q18",prompt:"A common application of a min-heap of size k over a stream:",options:["Maintain the k largest seen so far in O(log k) per item","Compute the median","Reverse the stream","Sort all items in O(n)"],correct:0,explanation:'If new item > heap-min (the kth largest), replace and sift. The heap acts as a moving "kth largest" filter.'},{id:"q19",prompt:"For the running median with two heaps, balance is restored by:",options:["Random selection","Move the root of the larger heap to the smaller heap","Sort both","Drop the larger heap"],correct:1,explanation:"Maintain |upper| - |lower| within {0, 1}. After every insert, top-balance to restore the invariant."},{id:"q20",prompt:"A d-ary heap (each node has d children) trades off:",options:["Shallower depth (log_d n) for slower sift-down (compare d children per step)","Sortedness","Worse asymptotic complexity","Memory only"],correct:0,explanation:"Lower depth speeds up decrease-key; sift-down per step costs more. Tunable for cache or specific workload mixes."}]},{id:"graph-basics",title:"Graphs — Representations & Reach",topic:"graph",difficulty:"Intermediate",summary:"Adjacency lists vs matrices, connectivity, and the algorithms that follow.",questions:[{id:"q1",prompt:"Adjacency list of a graph with V vertices and E edges uses memory:",options:["O(V)","O(V + E)","O(V * E)","O(V^2)"],correct:1,explanation:"Each vertex stores its incident edges once; total list length sums to 2E (undirected) or E (directed)."},{id:"q2",prompt:"Adjacency matrix needs how much memory?",options:["O(V)","O(V + E)","O(V^2)","O(E^2)"],correct:2,explanation:"A V-by-V boolean (or weight) matrix is constant per vertex pair."},{id:"q3",prompt:"BFS from a source on an adjacency list runs in:",options:["O(V)","O(V + E)","O(V log V)","O(V * E)"],correct:1,explanation:"Every vertex is enqueued/dequeued once and every edge explored once."},{id:"q4",prompt:"Topological sort works on:",options:["Any graph","Directed acyclic graphs (DAGs)","Undirected graphs only","Weighted graphs only"],correct:1,explanation:"Without cycles and with directed edges, a linear ordering respecting all edges exists."},{id:"q5",prompt:"Detecting a cycle in a directed graph uses:",options:["BFS only","DFS with three-color (white/gray/black) marking","Union-find","Topological sort by counting in-degrees"],correct:1,explanation:"A back-edge to a gray (in-progress) vertex proves a cycle. Kahn's indegree algorithm also detects cycles."},{id:"q6",prompt:"Union-find (DSU) is best suited for:",options:["Shortest paths","Connectivity queries / cycle detection in undirected graphs","Topological sort","Strongly connected components"],correct:1,explanation:"With path compression + union by rank, near-constant per operation — perfect for incremental connectivity."},{id:"q7",prompt:"Dijkstra requires which property of edge weights?",options:["All edges integer","All edges non-negative","All edges equal","All edges negative"],correct:1,explanation:'Negative edges break the greedy "first popped is final" invariant; use Bellman-Ford instead.'},{id:"q8",prompt:"Bellman-Ford on V vertices and E edges runs in:",options:["O(V + E)","O(V log V)","O(V * E)","O(V^2 log V)"],correct:2,explanation:"V - 1 passes, each relaxing every edge. Handles negative weights and detects negative cycles."},{id:"q9",prompt:"Minimum spanning tree algorithms include:",options:["BFS and DFS","Kruskal and Prim","Dijkstra and A*","Floyd-Warshall and Johnson"],correct:1,explanation:"Kruskal sorts edges and unions; Prim grows the tree by smallest connecting edge."},{id:"q10",prompt:"Strongly connected components are computed by:",options:["Single BFS","Kosaraju's or Tarjan's algorithm","Union-find","Dijkstra"],correct:1,explanation:"Both use DFS post-order; Kosaraju reverses the graph and reruns DFS, Tarjan tracks low-link values."},{id:"q11",prompt:"On a dense graph (E ~ V^2), adjacency matrix vs list trade-off favors the matrix because:",options:["O(1) edge-existence query and lower constant factors when most slots are filled","Lower memory","Faster BFS","Smaller cache footprint"],correct:0,explanation:"Lists pay 2-3x pointer overhead per edge; on dense graphs the matrix's O(V^2) cost is unavoidable anyway."},{id:"q12",prompt:"Dijkstra with a binary heap on V vertices and E edges runs in:",options:["O(V + E)","O((V + E) log V)","O(V * E)","O(V^2)"],correct:1,explanation:"Each edge may trigger a push (O(log V)); with lazy deletion, total heap operations are bounded by E."},{id:"q13",prompt:"A common cycle-detection trap on UNDIRECTED graphs using DFS is:",options:["Failing to skip the immediate parent — every edge would falsely look like a back-edge","Using recursion","Marking nodes visited","Iterating neighbors"],correct:0,explanation:"In undirected DFS, the edge back to the parent is the same edge you just used. Pass parent along and ignore it."},{id:"q14",prompt:"Kahn's algorithm for topological sort uses:",options:["DFS post-order","BFS over zero-indegree nodes, decrementing indegrees as edges are processed","Random ordering","Union-find"],correct:1,explanation:"If the final processed count is less than V, a cycle exists. The BFS naturally produces a valid topological order."},{id:"q15",prompt:"When would you reach for Floyd-Warshall over running Dijkstra V times?",options:["When you need all-pairs shortest paths AND want a simple O(V^3) algorithm that handles negative edges (no negative cycles)","When edges are non-negative and V is small","When the graph is sparse","Never"],correct:0,explanation:"On sparse graphs, V * Dijkstra wins (O(V * (V + E) log V)). Dense or negative-edge cases favor Floyd-Warshall."},{id:"q16",prompt:"Union-find's near-constant amortized cost comes from:",options:["Hashing","Path compression + union by rank/size combined","A balanced tree","Bloom filters"],correct:1,explanation:"Either optimization alone gives O(log n); combined, they give the inverse Ackermann α(n) — effectively constant."},{id:"q17",prompt:'In a directed graph, "reachability" between all pairs in O(V^2) per query can use:',options:["Transitive closure precomputed (warshall) — query is O(1) but build is O(V^3)","BFS per query","Only DFS","Union-find"],correct:0,explanation:"Trade preprocessing time for instant queries. If you only need a few queries, BFS-per-query (O(V + E) each) often wins."},{id:"q18",prompt:"A* differs from Dijkstra by:",options:["Using an admissible heuristic to guide the priority order toward the target","Sorting edges","Using BFS","Avoiding the priority queue"],correct:0,explanation:"A* pops by f = g + h. With h admissible (never overestimates), the first goal pop is the optimal distance, often much faster than Dijkstra."},{id:"q19",prompt:"When all edge weights are equal, Dijkstra reduces to:",options:["BFS","DFS","Floyd-Warshall","Bellman-Ford"],correct:0,explanation:"Equal weights mean each layer in Dijkstra's queue corresponds to a BFS layer. Use BFS directly for O(V + E) without the heap."},{id:"q20",prompt:"A bridge in an undirected graph is:",options:["Any edge in a cycle","An edge whose removal increases the number of connected components","Any tree edge","The longest edge"],correct:1,explanation:"Tarjan's bridge algorithm uses DFS low-link values: edge (u, v) is a bridge iff low[v] > disc[u]."}]},{id:"bfs-basics",title:"BFS — Layered Exploration",topic:"bfs",difficulty:"Intermediate",summary:"Breadth-first search invariants and where it dominates DFS.",questions:[{id:"q1",prompt:"BFS guarantees shortest paths in:",options:["Any graph","Unweighted graphs","Negative-weight graphs","Trees only"],correct:1,explanation:"Each enqueued vertex is reached at minimum hop count when every edge counts as one."},{id:"q2",prompt:"BFS uses which data structure?",options:["Stack","Queue","Heap","Hash map"],correct:1,explanation:"FIFO order ensures we exhaust all vertices at distance d before any at d + 1."},{id:"q3",prompt:"BFS visited set is necessary to:",options:["Speed up the queue","Prevent reprocessing and infinite loops on cycles","Sort vertices","Store distances"],correct:1,explanation:"Without visited tracking, a cycle re-enqueues forever; trees alone can skip it."},{id:"q4",prompt:'Multi-source BFS solves problems like "distance to nearest gate" by:',options:["Running BFS from each source separately","Seeding the queue with all sources at distance 0","Reversing the graph","Using Dijkstra"],correct:1,explanation:"All sources start at level 0; the first time a target is dequeued is the true minimum."},{id:"q5",prompt:"BFS time complexity on adjacency-list representation:",options:["O(V)","O(V + E)","O(V * E)","O(V^2)"],correct:1,explanation:"Each vertex enqueues once, each edge is checked once."},{id:"q6",prompt:"0-1 BFS uses what to handle edges of weight 0 or 1 in O(V + E)?",options:["Plain queue","Deque — 0-weight goes to front, 1-weight to back","Heap","Two stacks"],correct:1,explanation:'Deque preserves the "current layer first" property without paying O(log V) per relax.'},{id:"q7",prompt:"A bipartite-graph check is naturally:",options:["DFS counting back-edges","BFS / DFS two-coloring","Sorting nodes","Topological sort"],correct:1,explanation:"Alternate colors along edges; a conflict (same color across an edge) proves it's not bipartite."},{id:"q8",prompt:"On a grid, BFS adjacency is typically:",options:["Only the diagonal cells","4-direction (or 8 if specified) neighbors","All cells in the same row","Every cell within radius 2"],correct:1,explanation:"Up/down/left/right by default; problems may specify 8 with diagonals."},{id:"q9",prompt:"BFS memory in the worst case (e.g., a complete graph) is:",options:["O(1)","O(log V)","O(V)","O(V^2)"],correct:2,explanation:"The frontier can hold all V vertices; visited set also stores V entries."},{id:"q10",prompt:'Word ladder (transform "hit" to "cog") is best solved by:',options:["DFS","BFS over the word-difference graph","Dijkstra","Greedy"],correct:1,explanation:"Each step has unit cost; BFS returns the minimum number of transformations."},{id:"q11",prompt:"Bidirectional BFS speeds up shortest-path search by:",options:["Running BFS from source AND target, meeting in the middle — reducing exploration from b^d to ~2 * b^(d/2)","Using two queues","Sorting nodes","Hashing edges"],correct:0,explanation:"Exponential reduction when the graph is uniform. Requires the ability to BFS backward from the target."},{id:"q12",prompt:"A common BFS bug on grids is:",options:["Forgetting to mark a cell visited at enqueue time, leading to multiple enqueues of the same cell","Using a queue","Iterating neighbors","Using a hash set"],correct:0,explanation:"Marking only at dequeue lets the same cell pile up in the queue many times, blowing memory and time."},{id:"q13",prompt:"Rotting oranges (every minute, fresh oranges adjacent to rotten ones rot) is solved by:",options:["DFS","Multi-source BFS starting from all rotten cells at time 0","Sort by row","Dijkstra"],correct:1,explanation:"BFS levels equal minutes elapsed. The answer is the last level enqueued (or -1 if fresh oranges remain unreachable)."},{id:"q14",prompt:"Why does BFS find the shortest path on an unweighted graph but not on a weighted one?",options:['BFS treats every edge as cost 1; weighted edges break the "first reached = shortest" invariant',"BFS is slower on weighted graphs","BFS rejects weights","It does work on weighted graphs"],correct:0,explanation:"Use Dijkstra (non-negative) or Bellman-Ford (negatives allowed) when edge weights matter."},{id:"q15",prompt:"BFS to find the diameter of a tree uses:",options:["BFS once","BFS from any node to find a farthest node u; BFS from u to find the farthest from u — that distance is the diameter","DP on the tree","Dijkstra"],correct:1,explanation:"Two BFS sweeps. The proof relies on tree connectivity and uniqueness of paths."},{id:"q16",prompt:"0-1 BFS handles 0-weight edges by:",options:["Pushing to the front of a deque so they're explored as if they extend the current layer","Skipping them","Sorting edges","Using two queues"],correct:0,explanation:'Front-push preserves the "smallest cost out first" invariant without the O(log V) heap overhead.'},{id:"q17",prompt:"For a 4-direction grid BFS, neighbor offsets are typically stored as:",options:["Two parallel arrays of dx/dy","[(0, 1), (0, -1), (1, 0), (-1, 0)]","Both work","Hash map"],correct:2,explanation:"Either form iterates cleanly. Diagonal-inclusive needs 8 offsets; problem statement decides."},{id:"q18",prompt:"A snake-and-ladders board reduces to which graph problem?",options:["Shortest path in an unweighted directed graph; BFS from cell 1 finds min dice rolls to reach N","DP on dice values","Greedy roll selection","Topological sort"],correct:0,explanation:"Each cell has up to 6 outgoing edges (dice 1..6); ladders/snakes redirect. BFS finds the minimum-hop path."},{id:"q19",prompt:"Why might iterative-deepening DFS be preferred over BFS for very deep but sparse search trees?",options:["Same big-O time complexity but much lower memory (O(depth) vs O(branching^depth))","Faster than BFS","Avoids recursion","Finds longer paths"],correct:0,explanation:"IDDFS combines BFS optimality (in unweighted graphs) with DFS memory. Re-exploration cost is dominated by the deepest layer."},{id:"q20",prompt:"In BFS, you should record distance at:",options:["Dequeue time","Enqueue time (immediately when first discovered)","Either works equally","Never"],correct:1,explanation:"Recording at enqueue prevents re-enqueueing the same node. Dequeue-time recording allows duplicates and wastes work."}]},{id:"dfs-basics",title:"DFS — Deep First",topic:"dfs",difficulty:"Intermediate",summary:"Recursion, backtracking, and the shapes DFS exposes.",questions:[{id:"q1",prompt:"DFS uses which structure implicitly when implemented recursively?",options:["Queue","Heap","Call stack","Hash map"],correct:2,explanation:"Each recursive call pushes a frame; returns pop frames. Iterative DFS replaces this with an explicit stack."},{id:"q2",prompt:"DFS time complexity on adjacency-list representation:",options:["O(V)","O(V + E)","O(V^2)","O(V * E)"],correct:1,explanation:"Same as BFS — each vertex visited once, each edge inspected once."},{id:"q3",prompt:"DFS does NOT guarantee:",options:["Reaching every connected vertex","Finding shortest paths in an unweighted graph","Visiting each edge","Detecting cycles in directed graphs"],correct:1,explanation:"DFS may dive deep first; the first time it reaches a vertex isn't necessarily by the shortest hop count."},{id:"q4",prompt:"DFS recursion depth in the worst case is:",options:["O(1)","O(log V)","O(V)","O(V^2)"],correct:2,explanation:"A long chain forces V nested calls — beware stack overflow on huge graphs."},{id:"q5",prompt:"Number of connected components is typically counted by:",options:["BFS only","DFS or BFS, incrementing each unvisited start","Topological sort","Dijkstra"],correct:1,explanation:"Outer loop scans vertices; each unvisited start launches a DFS/BFS that floods one component."},{id:"q6",prompt:"Backtracking is DFS with which extra step?",options:["Sorting choices","Undoing state when returning up the recursion","Memoizing","Pruning by depth only"],correct:1,explanation:"Make a choice, recurse, then undo it so siblings see clean state."},{id:"q7",prompt:"DFS edge classification on a directed graph includes:",options:["Tree, back, forward, cross","Only tree and back","Heavy and light","Strong and weak"],correct:0,explanation:"Standard DFS analysis labels each edge by where it leads in the DFS tree."},{id:"q8",prompt:"A back-edge in a directed DFS tree indicates:",options:["Disconnection","A cycle","A self-loop only","Bipartiteness"],correct:1,explanation:"Reaching an ancestor that's still on the recursion stack closes a directed cycle."},{id:"q9",prompt:"Topological order via DFS uses:",options:["Pre-order push","Post-order push reversed","In-order push","Random order"],correct:1,explanation:"Finished vertices push onto a stack; reversing the stack gives a valid topological order."},{id:"q10",prompt:"Iterative DFS on a graph replaces recursion with:",options:["Queue","Explicit stack","Priority queue","Set"],correct:1,explanation:"A LIFO stack mirrors recursive depth-first behavior without growing the call stack."},{id:"q11",prompt:"Tarjan's SCC algorithm uses DFS plus:",options:["Low-link values tracking the smallest discovery time reachable from a node's subtree","Reverse-graph BFS","Hash sets","Topological sort"],correct:0,explanation:"When a node's discovery time equals its low-link, all nodes above it on the DFS stack form an SCC."},{id:"q12",prompt:"In Java's default stack size, a recursive DFS on a chain of ~10,000 nodes will:",options:["Run normally","Likely throw StackOverflowError","Use heap automatically","Be slower but succeed"],correct:1,explanation:"Default JVM thread stack is ~512KB-1MB; deep recursion exhausts it. Use -Xss to raise, or convert to iterative DFS."},{id:"q13",prompt:"A common backtracking bug is:",options:["Forgetting to undo state changes (visited flags, partial solutions) after recursion returns","Using too few base cases","Recursing too deeply","Returning the wrong type"],correct:0,explanation:`If you don't restore, sibling branches see polluted state and produce wrong answers — pair every "do" with a matching "undo".`},{id:"q14",prompt:"Counting islands in a grid is naturally:",options:["DFS or BFS flood-fill from each unvisited land cell","Sort cells","Dijkstra","Topological sort"],correct:0,explanation:'Each unvisited "1" launches a flood-fill that marks the whole connected component; count launches = islands.'},{id:"q15",prompt:"For permutations via backtracking, the swap-based variant is preferred because:",options:["It uses O(n) instead of O(n^2) extra space and avoids duplicate construction","It is the only correct way","It is recursive","It uses sets"],correct:0,explanation:'Swap current index with each choice, recurse, swap back. No "used" array, no per-level copying.'},{id:"q16",prompt:"Detecting a directed cycle with three-color DFS classifies a node as:",options:["white (unvisited), gray (in progress), black (fully processed); a gray-to-gray edge means cycle","red/yellow/green","sorted/unsorted","safe/dangerous"],correct:0,explanation:"Hitting a gray node means you're back on an ancestor still on the recursion stack — closed cycle."},{id:"q17",prompt:"DFS finds the LONGEST path in a graph:",options:["Always in O(V + E)","Only in DAGs (via topological-order DP); NP-hard in general graphs","Same complexity as shortest path","Never"],correct:1,explanation:"Longest-path is NP-hard on general graphs because cycles let you accumulate arbitrarily. DAGs avoid that."},{id:"q18",prompt:"Iterative DFS may visit nodes in a different order than recursive DFS because:",options:["Stack push order vs natural recursion order — pushing children left-to-right pops right-to-left","Iteration is buggier","Iteration uses BFS internally","Order is always identical"],correct:0,explanation:"To match recursive left-first order with an explicit stack, push children in reverse so left pops first."},{id:"q19",prompt:"When would BFS be preferred over DFS on a tree?",options:["Shortest hop-count or level-order results — DFS may dive past the target","Less memory","Easier to write","Always"],correct:0,explanation:'For shortest path or "by depth" reporting, BFS is canonical. DFS wins when memory is tight (O(height) vs O(width)).'},{id:"q20",prompt:'A "tree edge" in directed DFS leads to a:',options:["Previously visited node","White (unvisited) node — extends the DFS tree","Black node","Sibling"],correct:1,explanation:"Tree edges form the DFS spanning tree. Edges to gray nodes are back-edges; to black descendants, forward; to black non-descendants, cross."}]},{id:"dp-basics",title:"Dynamic Programming — Subproblems Don't Repeat",topic:"dp",difficulty:"Advanced",summary:"Overlapping subproblems, optimal substructure, and how to start a recurrence.",questions:[{id:"q1",prompt:"Dynamic programming requires which two properties?",options:["Greedy choice + sorted input","Optimal substructure + overlapping subproblems","Divide-and-conquer + base case","Two pointers + monotonic invariants"],correct:1,explanation:"Optimal substructure lets you build solutions from smaller ones; overlap justifies memoization."},{id:"q2",prompt:"Memoization caches results in:",options:["Top-down recursion","Bottom-up iteration","Both","Neither"],correct:0,explanation:"Memoization is the top-down form; bottom-up tabulation iterates in dependency order."},{id:"q3",prompt:"Climbing stairs (1 or 2 steps) maps to which classic sequence?",options:["Fibonacci","Catalan","Triangular numbers","Powers of two"],correct:0,explanation:"f(n) = f(n - 1) + f(n - 2) — Fibonacci with shifted base cases."},{id:"q4",prompt:"0/1 knapsack with n items and capacity W runs in:",options:["O(n)","O(n + W)","O(n * W)","O(2^n)"],correct:2,explanation:"A 2-D table of size n by W is filled in pseudo-polynomial time."},{id:"q5",prompt:"Longest Common Subsequence between strings of length m and n runs in:",options:["O(m + n)","O(m * n)","O(min(m, n))","O(2^(m + n))"],correct:1,explanation:"DP[i][j] depends on DP[i - 1][j - 1], DP[i - 1][j], DP[i][j - 1] — fill the m-by-n table once."},{id:"q6",prompt:"Why is Fibonacci with naive recursion exponential?",options:["Stack overflow","Each call re-solves the same subproblems","Floating-point error","Cache misses"],correct:1,explanation:"f(n - 1) and f(n - 2) both recompute f(n - 3) and below — exponential subtree."},{id:"q7",prompt:"Longest Increasing Subsequence has an O(n log n) algorithm using:",options:["Hash map","Patience sorting + binary search on tails","Heap","DFS"],correct:1,explanation:"Maintain the smallest tail for each LIS length; binary-search the insertion point per element."},{id:"q8",prompt:"Coin change (minimum coins to make amount A using unlimited copies) runs in:",options:["O(A)","O(n * A) where n is coin types","O(2^A)","O(n log A)"],correct:1,explanation:"DP[a] = 1 + min(DP[a - c]) over coins c; total work is O(n * A)."},{id:"q9",prompt:"Space optimization on knapsack-style DP often reduces 2-D to:",options:["1-D rolling array","Constant space always","O(n) regardless","No reduction is possible"],correct:0,explanation:"When DP[i] depends only on DP[i - 1], one row suffices; update right-to-left for 0/1."},{id:"q10",prompt:"A DP state should capture:",options:["Only the input size","All information needed for future decisions, nothing more","Every visited state","The full input history"],correct:1,explanation:"State design is about sufficiency: enough to recurse correctly, small enough to fit in memory."},{id:"q11",prompt:"Tabulation (bottom-up) vs memoization (top-down) — which always visits all states?",options:["Tabulation — fills the entire table","Memoization — recursion explores everything","Both visit all states","Neither"],correct:0,explanation:"Memoization only computes states actually reached from the root. Tabulation pays for unreachable states but avoids recursion overhead."},{id:"q12",prompt:"A DP solution where DP[i][j] depends only on DP[i-1][...] can usually be space-optimized to:",options:["Two 1-D arrays (current, previous), or a single array if dependencies are read carefully","O(1) always","No optimization possible","O(log n)"],correct:0,explanation:"Rolling arrays drop the outer dimension. For 0/1 knapsack, iterating capacity right-to-left enables a single 1-D array."},{id:"q13",prompt:"A trap when writing 0/1 knapsack with a 1-D rolling array is:",options:["Iterating capacity left-to-right — items get used multiple times (unbounded knapsack instead)","Using too much memory","Forgetting base case","Wrong recurrence"],correct:0,explanation:"Right-to-left iteration ensures each item is considered against the PREVIOUS row's values, not the current row's updates."},{id:"q14",prompt:'Why is "Edit Distance" not solvable greedily?',options:["Local choice (matching greedily) can force more edits later — must consider all three operations at each cell","Greedy is always wrong for strings","Edits can be negative","It is NP-hard"],correct:0,explanation:'"kitten" vs "sitting": a greedy alignment may miss the 3-edit optimum. DP considers all three ops at every (i, j).'},{id:"q15",prompt:"Longest Increasing Subsequence in O(n log n) uses:",options:["Binary search on a tails array; tails[k] = smallest end of any LIS of length k+1","A heap","Hash maps","DFS"],correct:0,explanation:"For each element, find its insertion point in tails. tails is not the LIS itself but its length equals the answer."},{id:"q16",prompt:"Matrix-chain multiplication DP has state DP[i][j] = min cost to multiply matrices i..j. Time complexity:",options:["O(n)","O(n^2)","O(n^3)","O(2^n)"],correct:2,explanation:"O(n^2) states; each transition tries n-1 split points. O(n^3) total. Knuth optimization can reduce some cases to O(n^2)."},{id:"q17",prompt:"A subtle bug with memoization in Python is:",options:["Using @lru_cache on a method whose `self` argument changes hashability","Memoization is always wrong","Recursion is too slow","Forgetting return statements"],correct:0,explanation:"lru_cache hashes all args including self. Mutating self between calls produces stale results; pass primitives instead."},{id:"q18",prompt:'Coin change "count number of ways to make amount A" with unlimited coins uses:',options:["1-D DP with outer loop over COINS, inner loop over amounts — order matters to avoid counting permutations","DFS","Greedy","Sorting"],correct:0,explanation:"Swapping the loops counts (1+2) and (2+1) as distinct; outer loop on coins yields combinations."},{id:"q19",prompt:'When is "Bitmask DP" appropriate?',options:["When state can be encoded as a subset of a small universe (n ≤ ~20), giving 2^n states","For string problems","For sorted arrays","Always"],correct:0,explanation:"Traveling Salesman uses DP[mask][i] = min cost to visit set `mask` ending at i. n=20 means ~20M states — feasible."},{id:"q20",prompt:"A signal that DP is the right tool is:",options:["Recursive brute force has exponential blowup AND many calls share identical (memoizable) arguments","Input is sorted","Greedy works","Two pointers apply"],correct:0,explanation:"Overlap + optimal substructure are the prerequisites. Without both, DP either over-engineers or returns wrong answers."}]},{id:"greedy-basics",title:"Greedy Algorithms — Local to Global",topic:"greedy",difficulty:"Intermediate",summary:"When a greedy choice actually leads to the optimum.",questions:[{id:"q1",prompt:"A greedy algorithm is correct only if the problem has:",options:["Overlapping subproblems","The greedy-choice property and optimal substructure","No constraints","Random inputs"],correct:1,explanation:"Without the greedy-choice property, locally best decisions can paint you into a globally worse corner."},{id:"q2",prompt:"Activity selection (max non-overlapping intervals) sorts by:",options:["Start time","End time","Duration","Profit"],correct:1,explanation:"Finishing earliest leaves the most room for future intervals — provably optimal."},{id:"q3",prompt:"Coin change with coin denominations {1, 2, 5, 10, 20, 50} is solvable greedily because:",options:["Coins are powers of two","The system is canonical (greedy gives optimal)","Any coin set works greedily","There are six coins"],correct:1,explanation:"Some denomination sets (like {1, 3, 4}) break greedy; {1, 2, 5, 10, 20, 50, 100} is canonical so greedy is exact."},{id:"q4",prompt:"Huffman coding builds an optimal prefix code by:",options:["DP over all merges","Repeatedly merging the two smallest-frequency nodes","Sorting symbols alphabetically","Hashing symbols to lengths"],correct:1,explanation:"Greedy merge with a min-heap produces the minimum total weighted path length."},{id:"q5",prompt:"Jump-game (reach the last index) greedy tracks:",options:["Furthest reachable index so far","Current sum","Visited cells","Backtrack steps"],correct:0,explanation:"If at any index i > furthest, you're stuck; otherwise greedily extend reach."},{id:"q6",prompt:"Why does greedy fail on the 0/1 knapsack in general?",options:["Items are indivisible — taking the densest may exclude the optimal combo","Capacity is unknown","Values are floats","It needs sorting"],correct:0,explanation:"Fractional knapsack is greedy; 0/1 isn't because you can't split an item that beats a denser one only partially."},{id:"q7",prompt:"Minimum number of platforms (interval scheduling on a single resource) is solved by:",options:["Sort starts and ends; sweep counting overlap","DP over all subsets","Hashing time slots","Topological sort"],correct:0,explanation:"Two sorted arrays merged with a sweep gives the peak overlap count."},{id:"q8",prompt:"Greedy proof techniques include:",options:["Exchange argument","Loop invariant","Cut argument (matroids)","All of the above"],correct:3,explanation:"Exchange argument, matroid theory, and invariant-style proofs are the canonical toolkit."},{id:"q9",prompt:"Gas station problem (start so you can complete a circuit) is greedy because:",options:["If total gas >= total cost, a valid start exists; reset start whenever the tank drops below 0","You must try every start","It uses DP","It needs a graph search"],correct:0,explanation:"A single linear pass with one running tank suffices; the reset point is the candidate answer."},{id:"q10",prompt:"Dijkstra is greedy because at each step it:",options:["Picks the unvisited vertex with smallest tentative distance and finalizes it","Sorts edges by weight","Uses a stack","Memoizes paths"],correct:0,explanation:"With non-negative weights, the smallest tentative distance is provably the true shortest distance."},{id:"q11",prompt:"Fractional knapsack is greedy because:",options:["Items are divisible — taking the highest value-per-weight ratio always leads to optimum","Items are integer-valued","Capacity is unlimited","Weight is irrelevant"],correct:0,explanation:"You can take a fraction of the marginal item. Without fractionality (0/1 knapsack), greedy can miss the optimum."},{id:"q12",prompt:"Kruskal's MST is greedy because it:",options:["Sorts edges and adds the cheapest that doesn't form a cycle","Uses DP","Picks edges randomly","Uses BFS"],correct:0,explanation:"Union-find detects cycles in near-constant time per check. Correctness is proved via the cut property."},{id:"q13",prompt:"A common greedy trap is:",options:["Assuming locally optimal choices always combine into a globally optimal solution","Greedy is too slow","Greedy uses too much memory","Greedy is recursive"],correct:0,explanation:"0/1 knapsack, longest path, traveling salesman — greedy fails because the greedy-choice property doesn't hold."},{id:"q14",prompt:"Meeting-rooms-II (minimum rooms needed) is solved greedily by:",options:["Sort by start; min-heap of end times; if earliest end <= current start, reuse that room","DP over intervals","BFS","Hash maps"],correct:0,explanation:"The heap size at any moment equals the rooms in use; max size during the sweep is the answer."},{id:"q15",prompt:'Why does greedy "always pick the largest coin" fail for denominations {1, 3, 4} when amount = 6?',options:["Greedy gives 4+1+1 (3 coins); optimal is 3+3 (2 coins) — the set isn't canonical","Greedy gives the right answer","Greedy uses too many coins always","Greedy is undefined here"],correct:0,explanation:"Non-canonical coin systems require DP. Test with small cases before assuming greedy correctness."},{id:"q16",prompt:"An exchange argument proves greedy by:",options:["Showing any optimal solution can be transformed into the greedy one without losing optimality","Sorting inputs","Brute forcing","Counting cases"],correct:0,explanation:"Swap a non-greedy choice for a greedy one and show the result is still optimal — induct to the full greedy solution."},{id:"q17",prompt:"Minimum number of arrows to burst balloons (intervals on x-axis) sorts by:",options:["End coordinate; shoot at the smallest end, then skip all balloons that include it","Start coordinate","Length","Random"],correct:0,explanation:"Just like activity selection. Each arrow handles a maximal set of overlapping intervals starting from the earliest end."},{id:"q18",prompt:"Greedy + priority queue is the pattern behind:",options:["Dijkstra, Prim, Huffman coding, scheduling with deadlines","BFS only","DFS only","DP"],correct:0,explanation:'A heap always exposes the current "best" item; many greedy algorithms boil down to "extract best, update, repeat".'},{id:"q19",prompt:'Why does "Jump Game II" (minimum jumps to reach end) yield to greedy?',options:['BFS levels: at each "current reach", extend to the furthest position any jump within reach can hit; layers = jumps',"Sort then scan","DFS","DP only"],correct:0,explanation:"It's implicit BFS over level boundaries — O(n) without a queue, using two pointers (current end, farthest reach)."},{id:"q20",prompt:"Greedy and DP differ because:",options:["Greedy commits to one choice per step; DP keeps all subproblem optima to combine later","Greedy uses more memory","DP is faster","They are equivalent"],correct:0,explanation:"When the greedy-choice property holds, greedy gives correct answers in less time. Otherwise DP is required."}]},{id:"recursion-basics",title:"Recursion — Trust the Smaller Problem",topic:"recursion",difficulty:"Beginner",summary:"Base cases, recursive cases, and the call stack.",questions:[{id:"q1",prompt:"Every recursive function must have:",options:["A loop","At least one base case","A helper function","A return value"],correct:1,explanation:"Without a base case, recursion never terminates — infinite calls and stack overflow."},{id:"q2",prompt:"Tail recursion is recursion where:",options:["The recursive call is the final action","There are exactly two calls","The function takes one argument","There is no base case"],correct:0,explanation:"Some compilers (notably not CPython) optimize tail calls into loops, eliminating stack growth."},{id:"q3",prompt:"Computing factorial(n) recursively uses how many stack frames?",options:["1","log n","n","2^n"],correct:2,explanation:"Each call recurses on n - 1; frames accumulate before the first return."},{id:"q4",prompt:"Default Python recursion limit is roughly:",options:["100","1000","10000","Unlimited"],correct:1,explanation:"Around 1000 frames; raise with sys.setrecursionlimit if needed (with caution)."},{id:"q5",prompt:"Backtracking explores a solution space by:",options:["DP","Recursing with choices and undoing on return","BFS layering","Greedy selection"],correct:1,explanation:"Try a choice, recurse, undo. Combined with pruning, it covers the search tree efficiently."},{id:"q6",prompt:"Naive recursive Fibonacci has time complexity:",options:["O(n)","O(n log n)","O(phi^n) (exponential)","O(n^2)"],correct:2,explanation:"The recursion tree branches exponentially because subproblems aren't cached."},{id:"q7",prompt:"Mutual recursion is:",options:["Two functions that call each other","A function that calls itself twice","Recursion using two arguments","Recursion with mutex locks"],correct:0,explanation:"A calls B which calls A — classic for parsing alternating grammar rules."},{id:"q8",prompt:"Converting recursion to iteration usually replaces the call stack with:",options:["A queue","An explicit stack","A heap","Nothing — just a loop"],correct:1,explanation:"Stack-based iteration mirrors what recursion does implicitly; sometimes a single loop variable suffices."},{id:"q9",prompt:"Memoization on a recursive function caches:",options:["Function source","Computed results keyed by arguments","Stack frames","Return types"],correct:1,explanation:"Repeated calls return the cached result; works when the function is pure."},{id:"q10",prompt:"Recursion is preferred over iteration when:",options:["Always","The problem decomposes naturally into smaller versions of itself (trees, divide-and-conquer)","You want top speed","Memory is tight"],correct:1,explanation:"Tree traversals, divide-and-conquer, and backtracking read clearly recursively; flat iteration suits sequential data."},{id:"q11",prompt:"CPython does not optimize tail calls because:",options:["Guido has stated it would obscure stack traces — debuggability beats the optimization","It is impossible","CPython is too old","It would break the GIL"],correct:0,explanation:"Schemes/Scala TCO compile tail calls to jumps. Python keeps frames for clearer tracebacks even at recursion-limit cost."},{id:"q12",prompt:"The recursion T(n) = 2 * T(n/2) + O(n) solves to:",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:1,explanation:"Master theorem case 2 — log_b(a) = log_2(2) = 1, matching the f(n) = n level. Merge sort follows this."},{id:"q13",prompt:"The recursion T(n) = T(n-1) + O(1) solves to:",options:["O(1)","O(log n)","O(n)","O(n^2)"],correct:2,explanation:"Each call peels one unit of work; n levels, constant per level. Factorial and naive list-sum follow this."},{id:"q14",prompt:"A trap in recursive solutions for trees is:",options:["Failing to handle the null/empty-subtree base case before dereferencing","Using too few arguments","Recursion always overflows","Pre-order is wrong"],correct:0,explanation:"Always `if not node: return ...` first. Skipping this on the very first call against an empty tree throws."},{id:"q15",prompt:"When converting recursion to iteration, a function with two recursive calls per frame:",options:["Requires an explicit stack — single loop variable doesn't suffice","Becomes a simple while loop","Cannot be converted","Becomes a queue"],correct:0,explanation:"Linear (tail) recursion fits a loop; tree recursion (Fibonacci-style) needs an explicit stack OR DP table."},{id:"q16",prompt:"Recursion is generally slower than iteration in CPython because:",options:["Each call allocates a frame object; function-call overhead is non-trivial in Python","Recursion is buggy","It uses more memory always","Lists are slower"],correct:0,explanation:"In C/Rust the gap is small. In Python, the per-call overhead can be 10x — preferred to iterate when both are clean."},{id:"q17",prompt:"Backtracking should prune branches by:",options:["Checking constraint violation BEFORE recursing (not after building the full candidate)","Sorting candidates","Random restart","Limiting depth only"],correct:0,explanation:"Early constraint checks cut exponentially large subtrees. N-Queens and Sudoku rely on this for tractability."},{id:"q18",prompt:"Why might you prefer recursion for tree traversals over iteration?",options:["The structure of recursion matches the tree's recursive definition — code is shorter and clearer","Recursion is faster","Iteration cannot traverse trees","Iteration needs more memory"],correct:0,explanation:"Mirroring data structure with code structure reduces bugs. Use iteration when depth might exceed the stack limit."},{id:"q19",prompt:"@lru_cache(maxsize=None) on a recursive function effectively turns it into:",options:["A memoized top-down DP","A tabulated bottom-up DP","Iteration","A generator"],correct:0,explanation:"It caches return values by argument tuple. Pure functions only; mutable arguments break the contract."},{id:"q20",prompt:"A subtle recursion bug in counting paths in a grid is:",options:["Counting (i, j) -> (i+1, j+1) twice via separate paths because of double-counting in subtree sums","Returning from base case prematurely","Returning before recursing","Forgetting +1"],correct:1,explanation:"Common to off-by-one base cases (e.g., returning 0 at the goal instead of 1). Verify with the tiniest grid."}]},{id:"sorting-basics",title:"Sorting — Trade-offs by Algorithm",topic:"sorting",difficulty:"Beginner",summary:"Stability, in-place, comparison vs non-comparison.",questions:[{id:"q1",prompt:"Worst-case comparison-sort lower bound (decision-tree argument):",options:["Omega(n)","Omega(n log n)","Omega(n^2)","Omega(2^n)"],correct:1,explanation:"A binary decision tree distinguishing n! permutations has depth log(n!) which is Omega(n log n)."},{id:"q2",prompt:"Quicksort's worst-case time:",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:2,explanation:"Bad pivots (sorted input + first/last pivot) degenerate to O(n^2). Random or median-of-3 pivots avoid it."},{id:"q3",prompt:"Merge sort's space complexity:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:2,explanation:"Standard merge sort allocates O(n) buffer for the merge step."},{id:"q4",prompt:"A sort is stable if:",options:["It never crashes","It preserves relative order of equal keys","It runs in O(n log n)","It uses O(1) space"],correct:1,explanation:"Stability matters when sorting by secondary keys after a primary sort."},{id:"q5",prompt:"Counting sort runs in O(n + k) when:",options:["Keys are arbitrary objects","Keys are integers with bounded range k","Input is already sorted","k is exponential in n"],correct:1,explanation:"Bucket each key by value; only practical when k is small (linear or less in n)."},{id:"q6",prompt:"Radix sort's time on n d-digit integers in base b:",options:["O(n log n)","O(d * (n + b))","O(n^2)","O(b^d)"],correct:1,explanation:"Stable bucket-sort per digit, d passes. Choosing b ~ n gives near-linear behavior."},{id:"q7",prompt:"Which sort is typically used by Python's sorted() / list.sort()?",options:["Quicksort","Heapsort","Timsort (hybrid merge + insertion)","Radix sort"],correct:2,explanation:"Timsort exploits existing runs and is provably stable, O(n log n) worst case."},{id:"q8",prompt:"Insertion sort is preferred over merge sort when:",options:["Input is huge","Input is small or nearly sorted","Input contains floats","Stability is irrelevant"],correct:1,explanation:"Insertion is O(n) on nearly-sorted data and has tiny constants on small subarrays."},{id:"q9",prompt:"Quickselect (find the kth smallest) average runtime:",options:["O(n)","O(n log n)","O(n log k)","O(k log n)"],correct:0,explanation:"Partition + recurse on one side only; recurrence T(n) = T(n/2) + O(n) is O(n) expected."},{id:"q10",prompt:"Heap sort is in-place but typically slower than quicksort because:",options:["Heap sort is O(n^2)","Worse cache locality (sift-down jumps across the array)","It is unstable","It uses recursion"],correct:1,explanation:"Sift-down hops by factors of 2, causing more cache misses than quicksort's contiguous partitions."},{id:"q11",prompt:"Why is Timsort the JDK's choice for Collections.sort on objects but not for int[]?",options:["Stability is required for object sort (preserving equal-key order); int arrays use dual-pivot quicksort for raw speed","Timsort is broken for primitives","int arrays can't be merged","Stability is irrelevant for objects"],correct:0,explanation:'Java guarantees stable sort for Collections; for primitives, no concept of "equal but distinct" applies, so quicksort wins on cache locality.'},{id:"q12",prompt:"Bucket sort's best-case complexity assumes:",options:["Input is uniformly distributed across the bucket range — each bucket holds ~n/k items, O(n) total","Input is sorted","k is small","Input is integers"],correct:0,explanation:"Worst case (all in one bucket) degenerates to whatever the inner sort is, often O(n^2). Uniform distribution is the assumption."},{id:"q13",prompt:"A common stability gotcha is:",options:["Heap sort is NOT stable — sift operations can reorder equal keys","Merge sort is unstable","Insertion sort is unstable","Quicksort is always stable"],correct:0,explanation:"Heap sort and standard quicksort are unstable. If you sort by a secondary key first, an unstable sort by the primary key destroys that ordering."},{id:"q14",prompt:"Quicksort's worst case (O(n^2)) on already-sorted input happens when:",options:["Pivot is always the first (or last) element — partition is maximally unbalanced","Input is random","Recursion is too deep","Comparisons fail"],correct:0,explanation:"Random pivot or median-of-3 avoids this. Introsort switches to heap sort if recursion depth exceeds 2 * log n."},{id:"q15",prompt:"External merge sort handles input larger than RAM by:",options:["Splitting into chunks that fit in memory, sorting each, then k-way merging from disk","Compressing the data","Sampling","Sorting in place"],correct:0,explanation:"Heap-based k-way merge streams sorted chunks from disk, writing the merged output. Underpins database sort-merge joins."},{id:"q16",prompt:"A 3-way quicksort (Dutch national flag partition) wins over standard quicksort when:",options:["Many duplicate keys — equal keys cluster in the middle and aren't recursed on","Always","Input is sorted","Few comparisons are allowed"],correct:0,explanation:"Standard quicksort treats every key as distinct. 3-way separates <pivot, =pivot, >pivot and recurses only on the outer regions."},{id:"q17",prompt:"Counting sort is NOT a comparison sort, so it bypasses the:",options:["Omega(n log n) lower bound — runs in O(n + k) for integer keys with range k","Stability requirement","Memory limit","Recursion depth"],correct:0,explanation:"Comparison sorts have a proven Omega(n log n) bound; non-comparison sorts exploit key structure (integers, fixed-width) to do better."},{id:"q18",prompt:"Why is in-place quicksort O(log n) auxiliary space, not O(1)?",options:["Recursion uses stack frames proportional to recursion depth","It allocates buffers","It uses heaps","It is actually O(1)"],correct:0,explanation:"Tail-call optimizing the larger partition keeps stack depth at O(log n). True in-place data movement (no extra arrays) gives the O(1) auxiliary memory CLAIM in literature, modulo recursion."},{id:"q19",prompt:"For sorting strings, radix sort beats comparison sort when:",options:["Strings share a fixed alphabet and many share prefixes — process digit by digit (MSD radix) for O(total chars)","Strings are all distinct","Strings are short","Comparison is cheap"],correct:0,explanation:"MSD radix groups strings by leading character, recursing into each bucket. Excellent for dictionaries and DNA sequences."},{id:"q20",prompt:"For sorting custom objects in Python, the recommended pattern is:",options:["Pass a `key=` function — Python calls it once per element (Schwartzian transform) for O(n) extra work","Override __lt__ on the class","Use cmp_to_key","Sort then post-process"],correct:0,explanation:"`key=` avoids per-comparison method dispatch. cmp_to_key works but is slower; __lt__ on the class is appropriate when the order is intrinsic."}]},{id:"searching-basics",title:"Binary Search — Beyond Sorted Arrays",topic:"searching",difficulty:"Intermediate",summary:"The monotonic predicate framework that powers binary search everywhere.",questions:[{id:"q1",prompt:"Binary search on a sorted array of n elements is:",options:["O(1)","O(log n)","O(sqrt n)","O(n)"],correct:1,explanation:"Each step halves the search space."},{id:"q2",prompt:"A common off-by-one bug in binary search is using:",options:["mid = (lo + hi) / 2 only","lo + (hi - lo) / 2 to avoid overflow","while lo <= hi vs lo < hi inconsistently with hi = mid - 1 vs hi = mid","Recursion"],correct:2,explanation:"The loop condition and the update rules must agree on whether hi is inclusive or exclusive."},{id:"q3",prompt:"Binary-search the answer is applicable when:",options:["Input is sorted","A predicate is monotonic over the candidate answer range","There is only one answer","The range is integer-valued"],correct:1,explanation:`If "is answer >= x feasible" is monotonic, you can bisect over x even when the original input isn't sorted.`},{id:"q4",prompt:"Finding the first index >= target uses:",options:["Lower bound","Upper bound","Sort + linear scan","Hash map"],correct:0,explanation:"Lower bound returns the leftmost insertion point preserving order."},{id:"q5",prompt:"Finding the leftmost true in a sorted boolean predicate [F, F, F, T, T, T] runs in:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:1,explanation:"Binary search on the monotonic predicate locates the transition."},{id:"q6",prompt:"Exponential search is useful when:",options:["Array size is unknown / streaming","Array is unsorted","Keys are unique","You need stability"],correct:0,explanation:"Double the bound until you overshoot, then binary search inside; total O(log target) even with unknown size."},{id:"q7",prompt:"Binary search on a rotated sorted array:",options:["Is impossible","Still runs in O(log n) by comparing halves to identify the sorted side","Requires O(n)","Needs to un-rotate first"],correct:1,explanation:"Each step determines which half is sorted, then decides whether target lies in it."},{id:"q8",prompt:"Find the peak in an array (each adjacent pair differs) can be done in:",options:["O(n)","O(log n)","O(n log n)","O(1)"],correct:1,explanation:"Binary search: if mid < mid + 1, a peak lies to the right; otherwise to the left or at mid."},{id:"q9",prompt:"Search a 2-D matrix where each row and column is sorted runs in:",options:["O(log(m * n))","O(m + n)","O(m * n)","O(min(m, n) * log(max(m, n)))"],correct:1,explanation:"Start at top-right: move down if too small, left if too large — O(m + n)."},{id:"q10",prompt:"A wrong mid = (lo + hi) / 2 (without lo + (hi - lo) / 2) can:",options:["Overflow in languages with fixed-width integers","Hang the loop","Produce wrong order","Be slower"],correct:0,explanation:"For very large lo + hi, the sum can exceed INT_MAX in C/Java; the safe form avoids it."},{id:"q11",prompt:"Finding sqrt(n) for integer n using binary search runs in:",options:["O(log n)","O(sqrt n)","O(n)","O(n log n)"],correct:0,explanation:"Bisect over [0, n] testing mid * mid vs n. Newton's method converges faster in floats but binary search wins for exact integer sqrt."},{id:"q12",prompt:'"Capacity to ship packages in D days" is best solved by:',options:["Binary search on capacity, with feasibility check counting required days","DP over packages","Sort and scan","Greedy assignment"],correct:0,explanation:"Monotonic predicate: bigger capacity = fewer days. Binary search the smallest capacity where days ≤ D."},{id:"q13",prompt:"A common binary-search bug is:",options:["Mismatched loop condition and pointer update (lo <= hi with hi = mid causes infinite loop)","Using recursion","Using mid = lo + (hi - lo) / 2","Returning the wrong type"],correct:0,explanation:"Pick a convention: closed [lo, hi] with hi = mid - 1, OR half-open [lo, hi) with hi = mid. Mixing them loops forever."},{id:"q14",prompt:"Python's `bisect.bisect_left` returns:",options:["Leftmost insertion point that keeps the list sorted","Index of the element if present, else -1","Rightmost insertion point","Length of the list"],correct:0,explanation:"bisect_left places duplicates before existing equal elements; bisect_right places them after. Pick based on intent."},{id:"q15",prompt:"Binary searching on REAL numbers (not integers) terminates when:",options:["hi - lo < epsilon (a tolerance), since exact equality may never hold with floats","lo == hi","mid * mid == target","After log n iterations"],correct:0,explanation:"Float arithmetic loses precision; use a small epsilon or fix iteration count (e.g., 100 iterations for 1e-30 precision)."},{id:"q16",prompt:"Find the median of two sorted arrays in O(log(min(m, n))) uses:",options:["Binary search on the partition position in the shorter array","Merge then index","Heap","Sort the concatenation"],correct:0,explanation:"Partition both arrays so that left half = right half in size; ensure left max ≤ right min. Binary search the cut."},{id:"q17",prompt:"Binary search assumes:",options:["Random access in O(1) and a sorted/monotonic predicate","Sorted input only","Integer indices","Unique elements"],correct:0,explanation:"Linked lists make binary search O(n) due to mid-pointer walk. Sorted-by-predicate (not by value) extends the technique."},{id:"q18",prompt:'For "find any element" (not first/last) in a sorted array, binary search returns:',options:["Any matching index — early exit on mid == target","Always the leftmost","Always the rightmost","The smallest index in the array"],correct:0,explanation:'Early exit avoids the trickier "find boundary" template. Use lower/upper bound when you need a specific occurrence.'},{id:"q19",prompt:'Why might "rotated sorted array" search return WRONG results with naive binary search?',options:["Standard binary search assumes monotonic order across the whole range — the rotation breaks that assumption at the pivot","Comparisons are too slow","It infinite-loops","It uses too much memory"],correct:0,explanation:"You must first determine which half is sorted (by comparing mid to lo/hi), then check whether the target lies within that sorted half."},{id:"q20",prompt:"Galloping search (exponential search) before binary search helps when:",options:["The target is likely near the start of a sorted (possibly unbounded) range","Input is unsorted","Memory is tight","Comparisons are costly"],correct:0,explanation:"Doubling the bound (1, 2, 4, 8...) finds an upper limit in O(log target), then binary search inside the bracket. Used in Timsort merges."}]},{id:"sliding-window-basics",title:"Sliding Window — Linear Subarray Scans",topic:"sliding-window",difficulty:"Intermediate",summary:"When two pointers shrink and grow to keep an invariant.",questions:[{id:"q1",prompt:"Sliding window is appropriate when:",options:["Input is sorted","Working with contiguous subarrays / substrings and the window invariant is monotonic","You need random access","The array contains negative numbers only"],correct:1,explanation:"A monotonic invariant means you can advance the right and shrink the left without re-scanning."},{id:"q2",prompt:"Longest substring without repeating characters runs in:",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:0,explanation:"Right pointer sweeps once; left advances on repeats. A hash map tracks last seen index."},{id:"q3",prompt:"Fixed-size window of length k over an array of length n iterates:",options:["k times","n times","n - k + 1 times","n * k times"],correct:2,explanation:"The window shifts one position at a time from index 0 to n - k."},{id:"q4",prompt:"Variable-size window expanding while a condition holds, then shrinking, runs in:",options:["O(n)","O(n log n)","O(n^2)","O(2^n)"],correct:0,explanation:"Each index is touched by left and right pointers at most once each — amortized linear."},{id:"q5",prompt:"Smallest subarray with sum >= S (positive numbers) is:",options:["Binary search","Sliding window","DP","Two heaps"],correct:1,explanation:"Grow until the sum hits S, then shrink while still valid, tracking the minimum length."},{id:"q6",prompt:"Sliding window fails outright when:",options:["Input has duplicates","Negative numbers break the monotonic invariant (e.g., subarray-sum problems)","You need O(n) space","The array is sorted"],correct:1,explanation:"Adding a negative can increase or decrease the sum — shrinking the window no longer guaranteed valid."},{id:"q7",prompt:"Maximum in every window of size k in O(n) uses:",options:["Heap of size k","Monotonic deque of indices","Sorted set","Two pointers"],correct:1,explanation:"Heap gives O(n log k); deque keeps decreasing values so the front is the window max — amortized O(1) per slide."},{id:"q8",prompt:'Anagram-substring search ("find all anagrams of p in s") is naturally:',options:["Sliding window with character-count comparison","Suffix array","DP","Hash of full substrings"],correct:0,explanation:"Maintain a length-26 counter inside the window; slide and update when frequencies match."},{id:"q9",prompt:"Two-pointer technique is essentially:",options:["Sliding window with both ends moving inward toward each other (often after sorting)","BFS","DP","Greedy partitioning"],correct:0,explanation:"Two-pointer is the broader family; sliding window with same-direction pointers is one variant."},{id:"q10",prompt:'When the constraint is "exactly k distinct" instead of "at most k", a common trick is:',options:["Sort and scan","Compute atMost(k) - atMost(k - 1)","Use DP","Binary search on k"],correct:1,explanation:'Two sliding-window passes counting "at most" subarrays; their difference is the "exactly" count.'},{id:"q11",prompt:"Minimum window substring (smallest window in s containing all chars of t) tracks:",options:['Required character counts, current window counts, and a "matched" counter to know when to shrink',"Hash of substrings","A heap of indices","Sorted character buckets"],correct:0,explanation:"Expand right until valid, shrink left while still valid, recording minimum window. Matched counter makes the validity check O(1)."},{id:"q12",prompt:'Why does sliding window NOT work for "longest subarray with sum exactly k" when negatives are allowed?',options:["Adding/removing an element can both increase and decrease the sum — invariant is non-monotonic","It is too slow","It uses too much memory","Negatives are unsupported"],correct:0,explanation:"Use prefix sums + hash map instead: for each prefix s, check if s - k was seen before."},{id:"q13",prompt:"A common bug in fixed-size sliding window is:",options:["Forgetting to remove the element leaving the window before adding the new right element","Using a queue","Computing the sum from scratch each step","Iterating too far"],correct:2,explanation:"Recomputing makes it O(n * k) instead of O(n). The whole point is to update incrementally: sum += new - old."},{id:"q14",prompt:'For "longest substring with at most K distinct characters", left-pointer advancement:',options:["Shrinks the window while distinct count exceeds K, decrementing per-character counts and removing when count hits 0","Moves left one step per right step","Resets to 0","Uses binary search"],correct:0,explanation:"When right adds a new distinct char beyond K, left advances until the distinct count drops back to K."},{id:"q15",prompt:"A monotonic-deque-based sliding maximum stores:",options:["Indices of elements in decreasing value order — front is the current max","Element values only","A heap of values","Frequency counts"],correct:0,explanation:"Storing indices lets you pop the front when it falls out of the window. Decreasing-order pops back-of-deque dominated by new entries."},{id:"q16",prompt:"Subarray-product less than K (positive integers) uses sliding window because:",options:["Multiplying a positive shrinks/grows monotonically — left can chase right safely","It uses binary search","It is DP","Products are always sorted"],correct:0,explanation:"For each right, number of valid subarrays ending at right = right - left + 1. Add these in one pass."},{id:"q17",prompt:"For sliding window over a string, the inner counter is usually:",options:["An array of size 26 (or 128) for ASCII — O(1) updates","A hash map","A balanced BST","A trie"],correct:0,explanation:"Array indexing by char code is faster than hash lookup. Hash maps shine for unbounded alphabets (Unicode)."},{id:"q18",prompt:"Why does sliding window naturally give O(n) instead of O(n^2)?",options:["Each index is touched by left and right pointers at most once each — total pointer movement is O(n)","It uses sorting","It uses recursion","It is binary search"],correct:0,explanation:'Even though the inner loop "looks" nested, amortized analysis shows each step is O(1) on average.'},{id:"q19",prompt:'Sliding window with hash map for "longest substring without repeating characters" advances left to:',options:["max(left, last_seen[char] + 1) when a duplicate is found","left + 1 always","right - 1","0"],correct:0,explanation:"Naively jumping left to last_seen + 1 may move left BACKWARD when an earlier duplicate is outside the window. Always take the max."},{id:"q20",prompt:'When the window invariant is "exactly k", convert to:',options:['atMost(k) - atMost(k - 1) using two "at most" sliding-window passes',"atLeast(k) - atLeast(k + 1)","Use a heap","Use DP"],correct:0,explanation:`Direct "exactly" is hard because windows aren't monotonic. "At most" is monotonic; their difference gives the exact count.`}]},{id:"two-pointers-basics",title:"Two Pointers — Coordinated Walks",topic:"two-pointers",difficulty:"Beginner",summary:"Same direction, opposite direction, fast and slow.",questions:[{id:"q1",prompt:"Two pointers from both ends of a sorted array find a target pair sum in:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:2,explanation:"Move the appropriate pointer inward each step; total work is linear."},{id:"q2",prompt:"Removing duplicates from a sorted array in place uses:",options:["One pointer","Two same-direction pointers (read, write)","A hash set","Sort and scan"],correct:1,explanation:"Read pointer scans; write pointer trails, only advancing on new values."},{id:"q3",prompt:"Reverse an array in place uses two pointers moving:",options:["Same direction","Opposite directions, swapping at each step","In a loop counting collisions","Randomly"],correct:1,explanation:"Swap the values at left and right, then move both inward."},{id:"q4",prompt:"Fast/slow pointer cycle detection in a linked list takes which space?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:0,explanation:"Just two pointers — no auxiliary set or stack."},{id:"q5",prompt:"Container with most water (max area between two vertical lines) is solved by:",options:["Sort then scan","Two pointers from both ends, moving the shorter line inward","DP","Greedy on heights"],correct:1,explanation:"Moving the taller line can only worsen the area; moving the shorter line might improve it."},{id:"q6",prompt:"Three-sum (triples summing to zero) typically runs in:",options:["O(n)","O(n log n)","O(n^2)","O(n^3)"],correct:2,explanation:"Sort, then for each anchor run two-pointer over the remainder — O(n^2) total."},{id:"q7",prompt:"Merging two sorted arrays in place from the back uses two pointers because:",options:["Front insertions cost O(n) per shift","Back has free space we can fill without overwriting unread data","Sort is faster from the back","Cache prefers reverse order"],correct:1,explanation:"When the second array fits in trailing slots of the first, comparing from the back avoids overwrites."},{id:"q8",prompt:"Partitioning an array around a pivot (Dutch national flag) uses how many pointers?",options:["One","Two","Three (low, mid, high)","Four"],correct:2,explanation:"Three-way partition keeps <pivot, =pivot, >pivot regions distinct in one O(n) pass."},{id:"q9",prompt:"Trapping rain water using two pointers needs which extra state?",options:["Heap of heights","Running max from each side","Stack of indices","Hash map"],correct:1,explanation:"Each side tracks the max seen so far; water at a position is min(leftMax, rightMax) - height."},{id:"q10",prompt:"Two pointers won't help when:",options:["Array is sorted","You need random access to arbitrary indices simultaneously","You're scanning a substring","Iterating both ends inward"],correct:1,explanation:"The technique relies on coordinated linear motion — arbitrary jumps break the amortization."},{id:"q11",prompt:"Why does two-pointer for pair-sum require a SORTED array?",options:["Sorted order means moving the smaller pointer can only increase sum, the larger can only decrease — directional control","Sorted is faster","Sorted uses less memory","It works on unsorted too"],correct:0,explanation:"On unsorted input, you can't deduce which pointer to move from the current sum vs target."},{id:"q12",prompt:"Four-sum (quadruples summing to target) using two-pointer typically runs in:",options:["O(n^2)","O(n^3)","O(n^4)","O(n log n)"],correct:1,explanation:"Fix two outer indices (O(n^2)), then two-pointer over the remainder (O(n)) — total O(n^3)."},{id:"q13",prompt:"A common bug in two-sum-on-sorted is:",options:["Failing to skip duplicates after a match when the problem asks for unique pairs","Using two pointers","Sorting first","Returning early"],correct:0,explanation:"After recording a pair, advance left past duplicates and right past duplicates before continuing."},{id:"q14",prompt:'Why does the "move shorter line inward" rule work for container-with-most-water?',options:["Moving the taller line cannot improve area (width shrinks, height capped by shorter line); only moving shorter offers any hope","It uses sorting","It is greedy","It uses DP"],correct:0,explanation:"A formal proof: if the shorter is on the left, any pair (left, k < right) has area ≤ left * (k - left+1) ≤ left * (right - left), so we lose nothing by skipping left."},{id:"q15",prompt:'In Python, "fast and slow" pointer cycle detection for a linked list uses:',options:["slow = slow.next; fast = fast.next.next — check fast and fast.next for None each step","Recursion","A hash set","BFS"],correct:0,explanation:"Check both fast and fast.next; either being None means no cycle (fast hit the end)."},{id:"q16",prompt:'Two-pointer "trapping rain water" achieves O(1) space by:',options:["Tracking left_max and right_max running maxes while pointers converge","Using a stack","DP arrays","A heap"],correct:0,explanation:"Whichever side has the smaller running max bounds the water at the current position — fill, then advance that side."},{id:"q17",prompt:"Dutch national flag (sort {0, 1, 2}) uses three pointers and runs in:",options:["O(n) time, O(1) space, single pass","O(n log n)","O(n^2)","O(n) time, O(n) space"],correct:0,explanation:"low/mid/high partition the array; mid advances on 1, swaps with low on 0 (then advances), swaps with high on 2 (without advancing mid)."},{id:"q18",prompt:"When does two-pointer LOSE to a hash map for two-sum?",options:["When the array is unsorted — sorting is O(n log n) but hash map gives O(n)","On sorted input","On small inputs","Never"],correct:0,explanation:"Hash map handles unsorted in one pass; two-pointer requires sorted input (a O(n log n) overhead unless already sorted)."},{id:"q19",prompt:"Removing the nth node from the end of a linked list in one pass uses:",options:["Two pointers with a gap of n — when fast reaches end, slow is at the node before the one to remove","Length count","Recursion","Reversal"],correct:0,explanation:"Initialize a dummy head; advance fast n+1 steps so slow ends at the predecessor of the target."},{id:"q20",prompt:"In partitioning around a pivot (Lomuto scheme), the two pointers represent:",options:['Boundary of the "≤ pivot" region (slow) and the scan position (fast)',"Heap roots","Sorted region edges","Hash slots"],correct:0,explanation:"When fast finds a value ≤ pivot, swap with arr[slow] and advance slow. After the scan, swap pivot into arr[slow]."}]},{id:"system-design-basics",title:"System Design — First Principles",topic:"system-design",difficulty:"Intermediate",summary:"Latency, throughput, consistency, and the obvious-once-you-see-it trade-offs.",questions:[{id:"q1",prompt:"Read-heavy traffic is most often offloaded using:",options:["Stronger primary database","Caching layer (in-memory or CDN)","Sharding writes","Synchronous replication"],correct:1,explanation:"Most reads hit a fast cache (Redis, Memcached, CDN edge); origin handles misses and writes."},{id:"q2",prompt:"CAP theorem says a distributed system under partition can guarantee:",options:["All three of C, A, P","At most two of consistency, availability, partition tolerance","Only availability","Only consistency"],correct:1,explanation:"During a network partition, you trade consistency for availability (or vice versa); P is non-negotiable in a real network."},{id:"q3",prompt:"Horizontal scaling means:",options:["Bigger machine","More machines coordinating","Faster CPU","Vertical replication"],correct:1,explanation:"Add nodes, distribute load. Vertical scaling buys a bigger box but hits hardware limits."},{id:"q4",prompt:"A load balancer's primary job is to:",options:["Cache responses","Distribute incoming requests across multiple backend instances","Authenticate users","Encrypt traffic"],correct:1,explanation:"Round-robin, least connections, or consistent hashing — spreads load and enables failover."},{id:"q5",prompt:"Database sharding partitions data by:",options:["Time of insertion only","A shard key (hash or range)","Random assignment","Table name"],correct:1,explanation:"Each shard holds a disjoint slice; the key determines which shard owns a row."},{id:"q6",prompt:"Consistent hashing's benefit over naive modulo is:",options:["Faster lookup","Minimal key remapping when nodes are added or removed","Stronger consistency","Better security"],correct:1,explanation:"Only ~K/N keys move when a node joins or leaves the ring, vs nearly all under hash-mod."},{id:"q7",prompt:"A message queue (e.g., Kafka, SQS) primarily provides:",options:["Strong consistency","Async decoupling between producers and consumers","Authentication","Caching"],correct:1,explanation:"Buffers spikes, decouples services, enables replay and downstream backpressure."},{id:"q8",prompt:"Idempotency in API design ensures:",options:["Requests are encrypted","Repeated identical requests have the same effect as one","Requests run faster","Server logs less"],correct:1,explanation:"Critical for retries — clients can safely resend without duplicate side effects (PUT, DELETE, GET)."},{id:"q9",prompt:"Eventually consistent systems guarantee:",options:["Linearizable reads","All replicas converge given enough time without new writes","Read-your-writes always","Atomic transactions"],correct:1,explanation:"Stronger models exist; eventual consistency is a baseline often acceptable for availability."},{id:"q10",prompt:"A CDN improves perceived latency primarily by:",options:["Compressing payloads","Serving static content from edge locations near the user","Faster origin servers","TLS optimization"],correct:1,explanation:"Geographic proximity is the dominant factor; round-trip time drops dramatically vs origin fetch."},{id:"q11",prompt:"SQL vs NoSQL: when does a relational store usually win?",options:["Complex ad-hoc joins, transactions across multiple entities, strong consistency requirements","Massive write throughput on single tables","Schemaless event logs","Geo-distributed availability"],correct:0,explanation:"NoSQL (document, key-value, wide-column) shines for high write volume, flexible schema, or horizontal scale. SQL's superpower is multi-row ACID and arbitrary joins."},{id:"q12",prompt:"A write-through cache differs from a write-back cache by:",options:["Write-through updates cache AND backing store synchronously; write-back updates cache and flushes later","Write-through is faster","Write-back is more durable","They are identical"],correct:0,explanation:"Write-through trades latency for durability; write-back risks data loss on crash but absorbs write spikes. Pick based on your durability budget."},{id:"q13",prompt:"A common misconception about microservices is:",options:["That they automatically improve performance — in reality, network hops add latency vs in-process calls","That they reduce code","That they require Docker","That they need NoSQL"],correct:0,explanation:"Microservices buy team autonomy, independent deployment, and fault isolation; they cost you latency, observability complexity, and distributed-transaction headaches."},{id:"q14",prompt:"Exactly-once delivery in distributed messaging is:",options:["Impossible in the strict sense; practical systems offer at-least-once + idempotent consumers OR transactional outbox","Trivially achieved with TCP","Provided by default by Kafka","A SQL feature"],correct:0,explanation:"Two Generals problem proves true exactly-once is unattainable. Idempotent processing with at-least-once is the standard workaround."},{id:"q15",prompt:"Optimistic locking uses which mechanism?",options:["Version number / timestamp checked on update; conflict triggers retry","Database mutex held for duration","OS-level file lock","Two-phase commit"],correct:0,explanation:"Pessimistic locks (SELECT FOR UPDATE) serialize and reduce throughput. Optimistic concurrency wins when conflicts are rare."},{id:"q16",prompt:"A read replica primarily provides:",options:["Horizontal scale for reads + redundancy; writes still go to the primary","Stronger consistency","Faster writes","Schema migration safety"],correct:0,explanation:"Most read replicas are async, so reads may be stale by milliseconds to seconds. Read-after-write consistency requires routing tricks (read-from-primary on recent writes)."},{id:"q17",prompt:"A bloom filter is best used to:",options:['Quickly reject "definitely not present" queries before hitting an expensive lookup; false positives possible, no false negatives',"Replace a hash map","Sort streaming data","Guarantee uniqueness"],correct:0,explanation:"Used in front of disk-backed stores (Cassandra, RocksDB) to avoid useless disk reads for non-existent keys."},{id:"q18",prompt:"A circuit breaker pattern protects a service from:",options:["Cascading failures by short-circuiting calls to an unhealthy dependency until it recovers","SQL injection","Cache misses","DDoS attacks"],correct:0,explanation:'After repeated failures, the breaker "opens" and fails fast; periodic probes determine when to "half-open" and re-test.'},{id:"q19",prompt:"CAP vs PACELC: PACELC adds which dimension?",options:["Latency vs consistency trade-off even when there is no partition (under normal operation)","Partition tolerance is optional","Availability is binary","It replaces CAP"],correct:0,explanation:"PACELC: if Partition, choose A or C; Else (normal), choose Latency or Consistency. DynamoDB chooses A+L; Spanner chooses C+C."},{id:"q20",prompt:"When should you reach for a graph database (Neo4j) over a relational one?",options:["Highly connected data with multi-hop traversal queries (friend-of-friend, fraud rings) — joins in SQL become prohibitive","Tabular reports","Time-series metrics","Document storage"],correct:0,explanation:"Graph DBs store edges as first-class citizens with O(1) hop traversal. A 5-hop SQL JOIN can outright kill query planners."}]}],i=o.reduce((e,t)=>(e[t.topic]||(e[t.topic]=[]),e[t.topic].push(t),e),{});function n(e){return o.find(t=>t.id===e)||null}const r={arrays:"Arrays",strings:"Strings","linked-list":"Linked Lists",stack:"Stacks",queue:"Queues",hashmap:"Hash Maps",tree:"Trees",bst:"Binary Search Trees",heap:"Heaps",graph:"Graphs",bfs:"BFS",dfs:"DFS",dp:"Dynamic Programming",greedy:"Greedy",recursion:"Recursion",sorting:"Sorting",searching:"Binary Search","sliding-window":"Sliding Window","two-pointers":"Two Pointers","system-design":"System Design"};export{i as Q,r as T,n as g};
